var ALL_Q = [
  {n:1,q:"Koji je <strong>stripovski junak</strong> roden u Valletti 1887. kao sin britanskog mornara i ciganske vjestice, a prvi se put pojavio u <em>Baladi o slanom moru</em>?",a:["corto maltese","corto"],p:[],e:"Corto Maltese fiktivni je stripski junak Huga Pratta (1967.). Mornar i avanturist s Malte, poznat po filozofskim monolozima i moralnoj ambivalentnosti, jedan od ikona europskog stripa."},
  {n:2,q:"Ime kojega bi se <strong>vojskovode</strong> antickog Kartage s materinskog jezika moglo prevesti kao 'dar Baalov' ili 'milost Baalova'?",a:["hanibal barka","hannibal barca","hanibal","hannibal"],p:[],e:"Hanibal Barka (247-183. pr. Kr.) poznat je po prelasku Alpa sa slonovima. Pobjeda kod Kane 216. pr. Kr. smatra se jednim od najsavrsenijih taktickih okruzenja u vojnoj povijesti."},
  {n:3,q:"Koja se najkraca <strong>rijec</strong> u Morseovu kodu koristi kao medunarodni signal za pomoc?",a:["sos"],p:[],e:"SOS (... --- ...) uveden je 1906. Berlinskom konvencijom. Odabran zbog tehnicke jednostavnosti, a ne kao kratica."},
  {n:4,q:"Po kojemu je ceskom <strong>studentu</strong> nazvan asteroid 1834, koji je 1969. otkrio astronom Lubos Kohoutek?",a:["jan palach","palach"],p:[],e:"Jan Palach (1948-1969) zapalio se na Václavskom trgu 16. sijecnja 1969. u znak protesta protiv sovjetske okupacije. Simbol je otpora komunizmu."},
  {n:5,q:"Biznismen Dimitrios Vikelas upamcen je kao prvi predsjednik koje medunarodne sportske <strong>organizacije</strong>, na cijem je celu bio od 1894. do 1896.?",a:["medunarodni olimpijski odbor","moo","ioc","olimpijski odbor"],p:["olimpij"],e:"Medunarodni olimpijski odbor (MOO/IOC) osnovan je 1894. na inicijativu Pierrea de Coubertina. Danas obuhvaca 206 nacionalnih olimpijskih odbora."},
  {n:6,q:"Koja je najveca zivuca <strong>vrsta glodavaca</strong>, cije ime na gvaranskom jeziku znaci 'vlasnik trave'?",a:["kapibara","vodenprase","capybara"],p:["glodav"],e:"Kapibara (Hydrochoerus hydrochaeris) moze teziti do 65 kg. Zivi uz rijeke i mocvare Juzne Amerike, izvrsno pliva i zivi u skupinama."},
  {n:7,q:"Koja je sovjetska <strong>videoigrica</strong> na Zapad lansirana 1986. pod sloganom 'From Russia with Love'?",a:["tetris"],p:[],e:"Tetris je dizajnirao Aleksej Pazitinov 1984. Pravu slavu donijela mu je verzija za Nintendo Game Boy 1989."},
  {n:8,q:"Koje je cuveno <strong>natjecanje ljepote</strong> 1951. pokrenuo Britanac Eric Morley?",a:["izbor za miss svijeta","miss svijeta","miss world"],p:["miss"],e:"Miss Svijeta jedno je od cetiri najprestizna natjecanja ljepote uz Miss Universe, Miss International i Miss Earth."},
  {n:9,q:"Na kojemu se <strong>polju</strong> u Lici 1493. dogodila bitka u kojoj je osmanska vojska porazila hrvatsku feudalnu vojsku pod vodstvom bana Derenecina?",a:["krbavsko polje","krbava"],p:[],e:"Krbavska bitka (1493.) jedna je od najtragicnijih u hrvatskoj povijesti. Gotovo cijela hrvatska plemicka elita poginula je ili zarobljena."},
  {n:10,q:"Na kojemu je TV <strong>kanalu</strong> koji je poceo emitirati 1. kolovoza 1981. prvi spot bio Video Killed the Radio Star?",a:["mtv","music television"],p:[],e:"MTV (Music Television) revolucionizirao je glazbenu industriju. U 1980-ima lansirao je karijere Michaela Jacksona, Madonne i brojnih drugih."},
  {n:11,q:"Vaganova, Cecchetti, Bournonville i Balanchine medunarodno su priznate metode poucavanja koje <strong>forme izvedbene umjetnosti</strong>?",a:["balet","ballet"],p:[],e:"Balet je klasicna plesna forma nastala na talijanskim renesansnim dvorovima u 15. st. Karakterizira ga kodificiran sustav pokreta i tehnika na prstima."},
  {n:12,q:"U znacenju 'sveto' ili 'zabranjeno' na tonganskom jeziku, koji se cetveroslovni <strong>pojam</strong> javlja u gotovo svim kulturama?",a:["tabu","taboo"],p:[],e:"Tabu potjece iz tonganskog 'tapu'. U europske jezike usao posredstvom kapetana Cooka. Freud ga je analizirao u djelu Totem i tabu (1913.)."},
  {n:13,q:"Koja je pop-<strong>pjevacica</strong> pocetkom 2019. pjesmama 7 Rings, Break Up i Thank U Next istovremeno zauzela prva tri mjesta Billboard Hot 100?",a:["ariana grande","ariana"],p:[],e:"Ariana Grande prva je izvodacica od Beatlesa 1964. koja je istovremeno zauzela prva tri mjesta Hot 100. Poznata po sopranskom falzetu."},
  {n:14,q:"U koje se <strong>naselje</strong> dvadesetak kilometara od LA-a preselio William Smith u seriji emitiranoj na NBC-ju od 1990. do 1996.?",a:["bel air","bel-air"],p:[],e:"Bel Air ekskluzivna je rezidencijalna cetvrt u zapadnom LA-u. Serija Princ iz Bel Aira lansirala je glumacku karijeru Willa Smitha."},
  {n:15,q:"Ep kojega je baroknog <strong>knjizevnika</strong> dopunio Ivan Mazuranic napisavsi 14. i 15. pjevanje?",a:["ivan gundulic","gundulic"],p:["gundul"],e:"Ivan Gundulic (1589-1638) najistaknutiji je pisac dubrovaske barokne knjizevnosti, autor epa Osman."},
  {n:16,q:"Koji je <strong>kviz</strong>, najpopularniji u Hrvatskoj i bivoj Jugoslaviji, pocinjao pjesmom Child of Vision grupe Supertramp?",a:["kviskoteka"],p:[],e:"Kviskoteka je bila kultna hrvatska TV kviz-emisija na HTV-u od 1985. do 2003. Vodio ju je Vlado Krsnik."},
  {n:17,q:"<strong>Tko</strong> je 2013. napisao pismo ruskom sveceniku pitajuci se je li odgovoran za smrt jer mu je puska oduzela ljudske zivote?",a:["mihail kalasnjikov","kalasnjikov","mikhail kalashnikov","kalashnikov"],p:[],e:"Mihail Kalasnjikov (1919-2013) tvorac je automatske puske AK-47, najrasprostranjenijeg vatrenog oruzja u povijesti."},
  {n:18,q:"Kako se zvala rimska <strong>svecanost</strong> u cast ocu vrhovnog rimskog boga tijekom prosinca, s gozbama i darivanjem?",a:["saturnalije","saturnalia"],p:[],e:"Saturnalije su bile rimski praznik u cast Saturna. Karakteriziralo ih je privremeno ukidanje drustvenih razlika."},
  {n:19,q:"Koji je oko 800 km dug <strong>hodocasnicki put</strong> Vijece Europe 1987. proglasilo prvom europskom kulturnom rutom?",a:["put svetog jakova","camino de santiago","camino","put sv jakova"],p:["santiago","jakob","camino"],e:"Camino de Santiago vodi do katedrale u Santiagu de Composteli. Danas ga prode vise od 300.000 hodocasnika godisnje."},
  {n:20,q:"Kako se zove jedno od najdojmljivijih <strong>zvijezda</strong> cijih sedam najsjajnijih zvijezda cini lik diva, a jos tri njegov pojas?",a:["orion","lovac"],p:[],e:"Orion je jedno od najprepoznatljivijih zvijezda. Tri sredisnje zvijezde (Alnitak, Alnilam, Mintaka) tvore Orionov pojas."},
  {n:21,q:"Kako nazivamo najmanju <strong>smjestajnu jedinicu</strong> povrsine 20-40 m2 cije ime dolazi od francuske rijeci za 'momka'?",a:["garsonijera","garsoniera"],p:[],e:"Garsonijera dolazi od fr. garcon (momak). Jedan od najpopularnijih tipova nekretnina u urbanim sredinama."},
  {n:22,q:"<strong>Tko</strong> se u rujnu 2021. u Springfieldu pridruzio Mirku Novoselu, Kresi Cosicu, Drazenu Petrovicu i Dinu Radi u NBA Kuci slavnih?",a:["toni kukoc","kukoc"],p:[],e:"Toni Kukoc (rod. 1968. u Splitu) trostruki je prvak NBA s Chicago Bullsima (1996., 1997., 1998.) uz Jordana i Pippena."},
  {n:23,q:"Kako se zove najdulja i najcvrca <strong>kost</strong> u ljudskom tijelu, cija duljina zauzima oko 27% visine tijela?",a:["bedrena kost","natkoljenicna kost","femur","bedrena"],p:["femur","bedrena","natkolj"],e:"Femur (bedrena kost) najdulja je i najmasivnija kost u tijelu. Zbog gustoce prezivljava tisuce godina u arheoloskim nalazistima."},
  {n:24,q:"Kako se zove amaterska sportska <strong>utrka</strong> autohtonih plovila u dolini Neretve, odrzava se od 1998. svake druge subote u kolovozu na 22.500 metara?",a:["maraton lada","maraton ladja"],p:["maraton","lad"],e:"Maraton lada tradicijska je utrka na Neretvi na autohtonim plovilima ladama. Dio je napora za ocuvanje tradicijskog brodogradnje."},
  {n:25,q:"Koju je mladu ekolosku <strong>aktivisticu</strong> casopis Time proglasio osobom 2019.?",a:["greta thunberg","greta","thunberg"],p:[],e:"Greta Thunberg (rod. 2003.) pokrenula je 2018. prosvjede ispred svedskog parlamenta. Pokret Fridays for Future prosiro se globalno."},
  {n:26,q:"Koji je trovolumenski luksuzni <strong>automobil</strong> s nepokretnim krovom nazvan po pastirima iz bivse francuske regije cije je srediste bio grad Limoges?",a:["limuzina","limousine"],p:[],e:"Limuzina je dobila ime po povijesnoj pokrajini Limousin. Dijeli se na standardne sedane i rastegnute (stretch limousines)."},
  {n:27,q:"Spot s amsterdamskog rock-festivala kojeg je <strong>benda</strong> 1988. postao prvi videospot izvodaca s podrucja bivse Jugoslavije prikazan na MTV-u?",a:["psihomodo pop","psihomodo"],p:[],e:"Psihomodo Pop je zagrebacki rock bend osnovan 1979. Njihov spot I Won't Be There prvi je jugoslavenski spot emitiran na MTV-u."},
  {n:28,q:"Temeljena na bestseleru Anthonyja Bourdaina, kako se zove humoristicna <strong>serija</strong> s Bradleyjem Cooperom o darovitom kuharu s problemom ovisnosti?",a:["dosje kuhinja","kitchen confidential"],p:["kuhinja","kitchen"],e:"Kitchen Confidential (2005.) temeljena je na bestseleru Bourdaina. Bradley Cooper tumaci kuhara Jacka Bourdaina."},
  {n:29,q:"Kako su 1916. Hugo Ball i Huelsenbeck u rjecniku pronasli <strong>rijec</strong> za 'drveni konjic' i nadjenuli ime novom umjetnickom pravcu?",a:["dada","dadaizam","dadaism"],p:[],e:"Dadaizam je avangardni pokret nastao 1916. u Zurichu kao reakcija na Primer svjetski rat. Koristio se nonsensnom i ironijom."},
  {n:30,q:"Uz koji se <strong>poluotok</strong> vezuje jedinstveni notacijski sustav jeong-gan-bo, nastao u vrijeme Sejonga Velikog?",a:["korejski poluotok","korejski","korea"],p:[],e:"Jeong-gan-bo bio je prvi istocnoazijski glazbeni notacijski sustav koji je prikazivao ritam, dinamiku i mjeru u pisanom obliku."},
  {n:31,q:"Kako se zove <strong>dio pisanog teksta</strong> u drami koji sadrzi opise scena i upute glumcima, uvijek pisan u kurzivu?",a:["didaskalije","didaskalija"],p:[],e:"Didaskalije su autorove upute u dramskom tekstu. Naziv potjece od grckog didaskein (poucavati)."},
  {n:32,q:"Koje je <strong>godisnje doba</strong> u naslovu Botticellijeva djela s Venerom, Merkurom, Zefirom, Kloris i Florom?",a:["proljece","proljetje","spring","primavera"],p:[],e:"Botticellijeva La Primavera (oko 1482.) jedna je od najcuvenijih renesansnih slika. Cuva se u Uffizi galeriji u Firenci."},
  {n:33,q:"Kako se <strong>prezivaju</strong> literarna braca Dmitrij, Ivan i Aljosa u remek-djelu Dostojevskog iz 1880.?",a:["karamazov","karamazovi"],p:[],e:"Braca Karamazovi (1880.) posljednji je i najopsezni roman Dostojevskog. Istrazuje teme Boga, slobodne volje i morala."},
  {n:34,q:"Koji je Kurosawin <strong>film</strong> iz 1950. posebno zainteresirao zapadnu publiku za japansku kinematografiju?",a:["rasomon","rashomon"],p:[],e:"Rasomon (1950.) prikazuje isti dogadaj kroz cetiri suprotstavljena iskaza. Osvoji Zlatnog lava u Veneciji 1951."},
  {n:35,q:"Kci Hermana II. Celjskog, udana za cara Zigmunda Luksemburskog — kako se zvala <strong>kraljica</strong> Hrvatske, Ugarske i Ceske?",a:["barbara celjska","barbara"],p:["celjsk","barbara"],e:"Barbara Celjska (oko 1392-1451.) mocna je i kontroverzna carica, zvana 'njemackom Messalinom'."},
  {n:36,q:"Ekonomska kriza u Meksiku krajem 1994., uzrokovana devalvacijom pesosa, kolokvijalno je poznata kao efekt kojeg <strong>alkoholnog pica</strong>?",a:["tekila","tequila"],p:[],e:"Tequila efekt opisuje kako je meksicka kriza iz 1994. brzo prenijela financijsku zarazu na Argentinu, Brazil i ostale latinoamericke ekonomije."},
  {n:37,q:"Kako se zove najstariji aktivni <strong>svjetionik</strong> na Jadranu i ujedno najsjeverniji u Hrvatskoj, izgraden 1818.?",a:["savudrija","savudria"],p:[],e:"Svjetionik Savudrija izgraden je 1818. pod austrijskom upravom. Kula je visoka 36 metara i jos uvijek aktivno sluz pomorskoj navigaciji."},
  {n:38,q:"Da bi burbon-viski bio burbon, mora sadrzavati najmanje 51% koje <strong>biljke</strong> iz porodice trava?",a:["kukuruz","corn","mais"],p:[],e:"Bourbon mora sadrzavati min. 51% kukuruza i odlezati u novim, spaljenima americkim hrastovim bacvama."},
  {n:39,q:"Alissa Eckert i Dan Higgins napravili su uvecani prikaz u obliku srebrenkaste kugle sa zagasitocrvenim bodljikama — <strong>cega</strong>?",a:["koronavirus","coronavirus","sars-cov-2","covid","covid-19"],p:["virus","korona","covid"],e:"Ilustracija SARS-CoV-2 iz CDC-a postala je jedna od najreprodiciranijih znanstvenih slika u povijesti."},
  {n:40,q:"Koji je bivsi australski <strong>plivac</strong>, peterostruki zlatni olimpijac na Igrama u Sidneyju, nosio nadimak Thorpedo?",a:["ian thorpe","thorpe"],p:[],e:"Ian Thorpe (rod. 1982.) najuspjesniji je australski olimpijac u plivanju s 5 zlatnih medalja."},
  {n:41,q:"Podrijetlom iz Andaluzije, kako se zove <strong>hladna juha</strong> s povrcem, najcesce na bazi rajcica?",a:["gazpacho"],p:[],e:"Gazpacho je hladna juha andaluzijskog podrijetla od svjezih rajcica, paprike, krastavca, luka, cesnaka i maslinovog ulja."},
  {n:42,q:"Divovski kelp Macrocystis pyrifera najveci je svjetski primjerak koje <strong>vrste organizama</strong>?",a:["alge","alga","algae","morske alge"],p:["alg"],e:"Macrocystis pyrifera moze narasti do 45 metara i 60 cm na dan. Zivi u hladnim obalnim vodama Tihog oceana."},
  {n:43,q:"Jacquesa Offenbacha, Karla Millockera i Johanna Straussa ponajprije vezujemo uz koji <strong>glazbeno-scenski oblik</strong>?",a:["opereta"],p:[],e:"Opereta je laki glazbeno-scenski zanr nastao sredinom 19. st. Offenbach je otac zanra, Strauss mladi vladao je beckom operetom."},
  {n:44,q:"Kojoj popularnoj <strong>TV seriji</strong> uvodna pjesma zapocinje stihovima 'Our whole universe was in a hot, dense state' kanadskog benda Barenaked Ladies?",a:["teorija velikog praska","big bang theory","the big bang theory"],p:["bang theory","veliki prasak"],e:"Teorija velikog praska (The Big Bang Theory, 2007-2019.) bila je jedna od najgledanijih americkih komedija."},
  {n:45,q:"Koji je hrvatski <strong>slikar</strong> iz 16. st. prozvan 'Michelangelom minijature'?",a:["juraj julije klovic","klovic","giulio clovio"],p:["klovic","clovio"],e:"Juraj Julije Klovic (1498-1578) bio je najcuveniji minijaturist renesanse. Roden u Grizzanu kraj Crikvenice."},
  {n:46,q:"S koje su <strong>planine</strong> u Juznoj Dakoti od 1927. do 1941. isklesane cetiri glave americkih predsjednika?",a:["mount rushmore","rushmore"],p:["rushmore"],e:"Mount Rushmore u Crnim brdima Juzne Dakote. Gutzon Borglum isklesao je likove Washingtona, Jeffersona, Roosevelta i Lincolna."},
  {n:47,q:"Koje je <strong>nacionalnosti</strong> kantautorica Anouk Teeuwe koja je 2013. pjesmom Birds predstavljala svoju zemlju na Eurosongu?",a:["nizozemska","holandija","netherlands"],p:["nizozemsk","holand"],e:"Anouk Teeuwe (rod. 1975.) nizozemska je pop i rock pjevacica. Na Eurosongu 2013. zauzela je 9. mjesto s pjesmom Birds."},
  {n:48,q:"Poznato je samo cetrnaest rijeci kojega <strong>pisca</strong> napisanih vlastitom rukom — ime potpisano 6 puta i rijeci 'od mene' na oporuci iz 1616.?",a:["william shakespeare","shakespeare"],p:["shakespeare"],e:"William Shakespeare (1564-1616) najutjecajniji je pisac engleskog jezika. Nije sacuvan ni jedan rukopis njegovih 37 drama."},
  {n:49,q:"Na UNESCO-ovu popisu od 1987., na sjeveru koje se <strong>drzave</strong> nalazi srednjovjekovno selo Holloko?",a:["madarska","hungary","madjarska"],p:["madar","hungar"],e:"Holloko je madarsko selo koje je ocuvalo tradicionalnu seosku arhitekturu i nacin zivota iz doba prije agrarne revolucije."},
  {n:50,q:"Vjencanje koje je, tada dvadesetogodisnje <strong>kraljice</strong>, 1840. pokrenulo trend bijelih vjencanih haljina?",a:["viktorija","victoria","kraljica viktorija"],p:["viktorij","victori"],e:"Kraljica Viktorija (1819-1901) udala se za princa Alberta 1840. u bijeloj haljini. Tradicija bijele vjencane haljine potjece od tog vjencanja."},
  {n:51,q:"Koji je hrvatski <strong>grad</strong> u talijanske vladavine poznat kao Abbazia, a ugostio je autoutrku Preluk 1931.?",a:["opatija"],p:[],e:"Opatija (tal. Abbazia) je odmaraliste na Kvarneru poznato od 19. st. Autoutrka Preluk bila je znacajan dogadaj u hrvatskoj motoristickoj povijesti."},
  {n:52,q:"Koji se <strong>latinski naziv</strong> skracenog oblika a. a. koristi za oznaku na spisima koji bi trebali biti pohranjeni u arhivu?",a:["ad acta"],p:[],e:"Ad acta (lat. za spise/arhiv) oznaka je da se dokument mora pohraniti. 'Staviti ad acta' znaci definitivno odbaciti neku stvar."},
  {n:53,q:"<strong>Tko</strong> je 1927. napisao da su vjerskska uvjerenja rodena iz covjekove potrebe da svoju bespomoćnost ucini prihvatljivom?",a:["sigmund freud","freud"],p:["freud"],e:"Sigmund Freud (1856-1939) u djelu Budućnost jedne iluzije (1927.) tvrdio je da je religija kolektivna neuroza iz ljudske bespomoćnosti."},
  {n:54,q:"U kojemu je <strong>sportu</strong> koji je sedam puta bio demonstracijski na ljetnim olimpijskim igrama Kuba najuspjesnija reprezentacija od 1992.?",a:["bejzbol","baseball"],p:["bejzb","baseb"],e:"Bejzbol je najmasovniji sport na Kubi. Kuba je dominirala medunarodnim natjecanjima, osvajajuci olimpijsko zlato 1992., 1996. i 2004."},
  {n:55,q:"Koju <strong>povijesnu osobu</strong> tumaci Gerard Depardieu u filmu Ridleyja Scotta 1492.: Osvajanje raja?",a:["kristof kolumbo","kolumbo","christopher columbus","columbus"],p:["kolumbo","columbus"],e:"Kristof Kolumbo (1451-1506) plovio je u ime spanjolske krune i 1492. dostigao Ameriku. Film iz 1992. obiljezio je 500. obljetnicu."},
  {n:56,q:"U kojoj se Bellinijevoj <strong>operi</strong> radnja dogada u Galiji 100. g. po Kristu, a druidska svecenicu Norma zaljubila se u rimskog prokonzula?",a:["norma"],p:[],e:"Norma (1831.) Vincenza Bellinija jedno je od remek-djela belkanta. Naslovna arija Casta Diva jedna je od najtezih opernih arija."},
  {n:57,q:"Uz Roberta i Soniju Delaunay, slikar František Kupka bio je najznacajniji predstavnik kojega <strong>umjetnickog pravca</strong> — oblika analitickog kubizma?",a:["orfizam","orphism"],p:["orfiz","orphi"],e:"Orfizam je apstraktni pravac nastao oko 1912. koji je kubisticke forme spajao s cistim bojama. Naziv mu je dao Guillaume Apollinaire."},
  {n:58,q:"Kako se zove cehoslovacka <strong>animirana serija</strong> o dvojici nespretnih ali mastovitih majstora, nastala sredinom 1970-ih?",a:["a je to","pat i mat","pat and mat"],p:["pat i mat","a je to"],e:"Pat i Mat (A je to!, 1976.) cehoslovacka je animirana serija. Svaka epizoda prikazuje dvojicu majstora koji rjesavaju probleme na komicno originalan nacin."},
  {n:59,q:"Koji je kultni <strong>redatelj</strong> u autobiografiji Moj posljednji uzdah napisao: 'Amerikanci imaju nedostataka, ali su ljudi od rijeci'?",a:["luis bunuel","bunuel"],p:["bunuel"],e:"Luis Bunuel (1900-1983) bio je spanjolski nadrealisti redatelj. Diskretni sarm burzaozije (1972.) donio mu je Oscar za strani film."},
  {n:60,q:"Utemeljeno 1992. u provinciji Gauteng, naselje Kleinfontein iskljucivo je bijela enklave — na sjeveroistoku koje <strong>drzave</strong>?",a:["republika juzna afrika","juzna afrika","south africa"],p:["juzna afrik","south afric"],e:"Kleinfontein je afrikaneska enklave u Juznoj Africi, jedno od rijetkih mjesta gdje se gotovo iskljucivo govori afrikaans."},
  {n:61,q:"Kojim nazivom francuskog podrijetla zovemo <strong>osobu</strong> koja kod igara na srecu pomaze bankaru dijeleći karte i manipulirajuci zetonima?",a:["krupje","croupier"],p:["krupj","croupi"],e:"Krupje (fr. croupier) je sluzbenik kockarnice koji vodi igre za stolom. Naziv potjece od starofrancuskog 'croupe'."},
  {n:62,q:"U kojoj je atletskoj skakackoj <strong>disciplini</strong> danas zabranjena tehnika 'volzing' koju je osamdesetih popularizirao David Volz?",a:["skok s motkom","skok motkom","pole vault"],p:["motkom","pole"],e:"Skok s motkom jedna je od najtehnicnijih atletskih disciplina. Tehnika volzing (zakretanje s licem prema motki) zabranjena je kao neravnopravna."},
  {n:63,q:"Koji se <strong>proces</strong> u kemiji definira kao difuzija kojom se izjednacuju koncentracije dviju otopina odijeljenih polupropusnom membranom?",a:["osmoza","osmosis"],p:["osmoz"],e:"Osmoza je kljucan biokemijski proces za regulaciju vode u stanicama. Reverzna osmoza primjenjuje se u prosciscavanju vode i desalinizaciji."},
  {n:64,q:"Megalodon je izumrla vrsta i predak koje danasnje <strong>zivotinje</strong>, predatora iz porodice Lamnidae, cije ime znaci 'veliki zub'?",a:["velika bijela psina","bijela psina","great white shark","ajkula"],p:["psina","shark","ajkul"],e:"Velika bijela psina jedina je zivuci srodnik megalodona koji je izumro prije oko 3,6 milijuna godina."},
  {n:65,q:"Nazvan po britanskom premijeru iz 19. st., Stanley je glavni grad kojeg <strong>arhipelaga</strong> u juznom Atlantiku?",a:["falklandsko otocje","falklandski otoci","falklands","malvinski otoci"],p:["falkland","malvin"],e:"Falklandski otoci britanski su prekomorski teritorij. Argentinsko-britanski sukob 1982. poznat je kao Falklandski rat."},
  {n:66,q:"U kojemu se <strong>stoljecu</strong> odvila Bitka kod Toursa u kojoj su Franci pod Karlom Martelom porazili vojsku Abdula Rahmana?",a:["osmo","8. stoljece","732","osmo 732"],p:["osm","732"],e:"Bitka kod Toursa (732.) jedna je od najvaznijih europskih bitaka. Karl Martel zaustavio je omejidsku ekspanziju prema sjeveru Europe."},
  {n:67,q:"Poznato i kao tran, ulje koje se <strong>zivotinje</strong> koristilo u javnoj rasvjeti do kraja 19. st., kada je zamijenjeno kerozinom?",a:["kitovi","kit","whale"],p:["kit","whale"],e:"Kitovo ulje bio je kljucan izvor energije za rasvjetu. Zamjenom kerozinom spasene su kitove populacije od izumiranja."},
  {n:68,q:"U videoigri Brutal Legend, pjevac kojeg je <strong>benda</strong> posudio glas liku Kill Master?",a:["motorhead","motörhead","lemmy kilmister","lemmy"],p:["motorh","lemmy","kilmist"],e:"Lemmy Kilmister (1945-2015), frontman Motorheada, posudio je glas i lik Kill Masteru u igri Brutal Legend (2009.)."},
  {n:69,q:"Vecina radnje kojega je <strong>bildungsromana</strong> njemackog nobelovca smjestena u sanatorij Berghof nedaleko od Davosa?",a:["carobna gora","der zauberberg","magic mountain"],p:["carobn","zauberb"],e:"Carobna gora (Der Zauberberg, 1924.) Thomasa Manna remek-djelo je njemacke knjizevnosti, alegorija europske kulture pred Prvim svjetskim ratom."},
  {n:70,q:"Kojega je legendarnog <strong>kantautora</strong> Bob Johnston vidio kao 'Mesiju s usnom harmonikom'?",a:["bob dylan","dylan"],p:["dylan"],e:"Bob Dylan (rod. 1941.) dobitnik je Nobelove nagrade za knjizevnost 2016. Jedan od najutjecajnijih glazbenika 20. st."},
  {n:71,q:"S kojom africkom <strong>drzavom</strong> svoje latinizirano prezime dijeli humanist Toma koji je 1519. postao skaradinski biskup?",a:["niger"],p:[],e:"Toma Niger (Toma Crni, oko 1450-1531) bio je hrvatski humanist i diplomat. Njegovo prezime latinizirano od hrv. 'crn'."},
  {n:72,q:"Na ikonskoj fotografiji Alberta Korde iz ozujka 1960., originalnog naziva Guerrillero Heroico, nalazi se poprsje koje <strong>osobe</strong>?",a:["ernesto che guevara","che guevara","che"],p:["che","guevara"],e:"Fotografija Guerrillero Heroico snimljena je 5. ozujka 1960. u Havani. Jedna je od najreprodiciranijih fotografija u povijesti."},
  {n:73,q:"S kojom spiralnom <strong>galaksijom</strong> ime dijeli radijska emisija koja vise od 20 godina educira javnost o svemiru?",a:["andromeda"],p:[],e:"Andromeda (M31) najblixa je spiralna galaksija Mlijecnom putu, udaljena oko 2,5 milijuna svjetlosnih godina."},
  {n:74,q:"Nakon Maheova krimicca Angoroj, horor Incubus iz 1966. drugi je film u potpunosti realiziran na kojemu <strong>jeziku</strong>?",a:["esperanto"],p:[],e:"Esperanto je planski jezik koji je 1887. stvorio Ludwik Lazarus Zamenhof. Film Incubus (1966.) jedini je americko-kanadski film na esperantu."},
  {n:75,q:"Nazvana prema lokalnom mitoloskom bicu Tonton Macoute, bila je posebna okrutna operativna jedinica kakve <strong>karipske drzave</strong>?",a:["haiti"],p:[],e:"Tonton Macoutes bila je tajna policija diktature Duvaliera na Haitiju. Ime dolazi od haitijskog folklora."},
  {n:76,q:"Koji se <strong>dio pribora</strong> za crtanje, uz pseenicu i cekic, nalazio u grbu Demokratske Republike Njemacke?",a:["sestar","sirkalo","compass"],p:["sestar","sirkalo"],e:"Sestar u grbu DDR-a simbolizirao je inteligenciju i strucni rad, dok su srp i cekic predstavljali radnike i seljake."},
  {n:77,q:"Bivsa juznoafricka plivacica Charlene Lynette Wittstock 2011. postala je princeza udavsi se za kojega <strong>monaha</strong>?",a:["albert ii grimaldi","albert od monaka","prince albert","albert ii"],p:["albert","grimaldi"],e:"Albert II. Grimaldi (rod. 1958.) vladar je Monaka od 2005. Ozenio se Charlene Wittstock u srpnju 2011."},
  {n:78,q:"Nastala kao stopljenica kontinenta i filmske nagrade, kako se zove godisnja <strong>nagrada</strong> za najboljeg europskog kosarkasa?",a:["euroscar"],p:[],e:"Euroscar je godisnja nagrada za najboljeg europskog kosarkasa koja se dodjeljuje od 1979. Nastala je kombinacijom 'Europa' i 'Oscar'."},
  {n:79,q:"Imaginarna jedinica i uvedena je jer njezin kvadrat iznosi koji <strong>cijeli broj</strong>?",a:["minus 1","-1"],p:["minus 1","-1"],e:"Imaginarna jedinica i definirana je kao kvadratni korijen od -1, tj. i^2 = -1. Kompleksni brojevi temelj su moderne matematike i fizike."},
  {n:80,q:"Kako se zove <strong>mjesavina etericnih ulja</strong> limuna, klincica, eukaliptusa, ruzmariana i kore cimeta, navodno korištena da zastiti pljackas grobova u 14. st.?",a:["lopovsko ulje","thieves oil","four thieves"],p:["lopovsk","thieves"],e:"Lopovsko ulje (Thieves Oil) etericna je smjesa s antibakterijskim svojstvima."},
  {n:81,q:"U pet kategorija jacine, Saffir-Simpsonova ljestvica koristi se za mjerenje i ucinak koje <strong>prirodne pojave</strong>?",a:["uragan","ciklon","hurricane","tajfun"],p:["uragan","ciklon","hurric","tajfun"],e:"Saffir-Simpsonova ljestvica razvrstava tropske ciklone u 5 kategorija prema brzini vjetra. Kategorija 5 oznacava brzinu iznad 252 km/h."},
  {n:82,q:"Koji se smedi <strong>umak</strong> kao jedan od pet temeljnih umaka francuske kuhinje spravljla od zaprske brasna s temeljem i pastom od rajcice?",a:["espagnole","spanjolski umak","sauce espagnole"],p:["espagnol","spanjolsk"],e:"Espagnole (spanjolski umak) jedan je od pet 'majcinskih umaka' po Auguste Escoffieru."},
  {n:83,q:"Poema Dionisiosa Solomosa sluzbenahimna je Grcke. Koja jos <strong>drzava</strong> od 1966. koristi taj isti tekst kao svoju nacionalnu himnu?",a:["cipar","cyprus"],p:["cipar","cyprus"],e:"Himna na slobodu najdulja je nacionalna himna na svijetu (158 strofa). I Grcka i Cipar sluzbeno koriste samo prve dvije strofe."},
  {n:84,q:"Lijecnik Bernard Kouchner bio je 1971. jedan od osnivaca koje meduarodne humanitarne <strong>organizacije</strong> za hitnu medicinsku pomoc?",a:["lijecnici bez granica","medecins sans frontieres","msf","doctors without borders"],p:["bez granica","sans frontieres","msf"],e:"Lijecnici bez granica (MSF) osnovani su 1971. u Parizu. 1999. dobili su Nobelovu nagradu za mir."},
  {n:85,q:"Koji je <strong>pas</strong> bio 'u igri' pri prvoj dodjeli Oscara za najboljeg glumca, ali je Akademija odlucila da nagrada pripada Emilu Janningsu?",a:["rin tin tin"],p:["rin tin"],e:"Rin Tin Tin bio je njemacki ovckar spašen iz rovova Prvog svjetskog rata. Postao je holivudska zvijezda u 27 nijemih filmova."},
  {n:86,q:"Pod kojim je imenom poznatiji perzijski <strong>pjesnik</strong> iz 14. st. Muhamed Semsudin, koji je u djetinjstvu naucio Kuran napamet?",a:["hafiz","hafez"],p:["hafiz","hafez"],e:"Hafiz (oko 1315-1390) jedan je od najcuvenijih perzijskih pjesnika. Njegovo ime znaci 'onaj koji pamti Kuran'. Divan mu je remek-djelo."},
  {n:87,q:"Koji je trodnevni glazbeni <strong>festival</strong> iz 1967. uz nastupe Janis Joplin, Otisa Reddinga i Ravija Shankara bio vrhunac kalifornijskog ljeta ljubavi?",a:["monterey pop festival","monterey"],p:["monterey"],e:"Monterey Pop Festival (lipanj 1967.) smatra se prvim velikim rock festivalom i pocetkom 'ljeta ljubavi'. Otkrio je Jimi Hendrixa americkoj publici."},
  {n:88,q:"Za kojeg Isusova <strong>apostola</strong> pise da je razapet na kriz u obliku slova X u Patrasu?",a:["andrija","andrew","sveti andrija"],p:["andrij","andrew"],e:"Sveti Andrija razapet je na dijagonalni kriz (Crux decussata). Na tom krizu su zastave Skotske, Rusije i Srbije."},
  {n:89,q:"Muzej Gauguina smjesten je u jugozapadnom dijelu kojega <strong>otoka</strong>, najveceg u otocju Drustveni otoci?",a:["tahiti"],p:[],e:"Tahiti je najveci otok Francuske Polinezije. Gauguin je zivio tamo od 1891. i naslikao neka od svojih najcuvenijih djela."},
  {n:90,q:"Za crtani film Rabbit of Seville iz 1950. Carl Stalling glazbu je temeljio na uvertiri kojega <strong>skladatelja</strong> (1792-1868.)?",a:["gioacchino rossini","rossini"],p:["rossini"],e:"Gioacchino Rossini talijanski je operni skladatelj, autor Seviljskog brijaca (1816.). Carl Stalling koristio je njegovu glazbu u Looney Tunes."},
  {n:91,q:"S kojim <strong>alkaloidom</strong> iz skupine ksantina ime dijeli Googleov sustav za indeksiranje mreznih stranica, dovršen 2010.?",a:["kofein","caffeine"],p:["kofein","caffein"],e:"Kofein (C8H10N4O2) najsire je konzumirani psihoaktivni spoj. Googleov Caffeine bio je algoritam koji je ubrzao indeksiranje weba."},
  {n:92,q:"Album No Strings Attached kojega je <strong>boy benda</strong> prodao 2,4 milijuna primjeraka u prvom tjednu 2000., sto ga cini tada najbrze prodavanim americkim albumom?",a:["nsync","n sync"],p:["nsync"],e:"NSYNC je boy band osnovan 1995. u Orlandu. Album No Strings Attached postavio je rekord u prvom tjednu prodaje 2000."},
  {n:93,q:"Prema latinskom za 'cudo', kako se zove vrsta srednjovjekovne sakralne <strong>drame</strong> u kojoj se prikazuju dogadaji iz zivota svetaca?",a:["mirakul","miracle play","mirakl"],p:["mirakul","miracl"],e:"Mirakuli su vrsta vjerskih drama popularnih od 12. do 16. st."},
  {n:94,q:"Gradani koje su komunisticke <strong>drzave</strong> anonimno pisali pisma koja je BBC vise od 20 godina citao u emisiji Pisma bez potpisa?",a:["istocna njemacka","ddr","gdr","njemacka demokratska republika"],p:["istocna njem","ddr","gdr"],e:"Pisma bez potpisa bila je BBC-jeva emisija na njemackom jeziku od 1952. do 1975. Gradani DDR-a pisali su o zivotu iza Zeljezne zavjese."},
  {n:95,q:"Nazvana po staroj kineskoj drzavi, kako se zvala kineska <strong>dinastija</strong> koja je vladala Kinom od 618. do 907.?",a:["tang","tang dinastija"],p:["tang"],e:"Dinastija Tang (618-907.) zlatno je doba kineske civilizacije, poznato po cvatu poezije, ceramike i Putom svile."},
  {n:96,q:"Smjesten izmedju Lopara, Krka, Prvica i Golog otoka, kako se zove drugi najzeleniji <strong>otok</strong> na Jadranu, koji je od 1948. do 1988. bio kazneno-popravni dom za zene?",a:["sveti grgur","grgur"],p:["grgur"],e:"Sveti Grgur je nenaseljen otok u Kvarnerskom zaljevu. Za komunisticke vlasti bio je zatvor za politicke zatvorenice."},
  {n:97,q:"Kako se zvao religijski <strong>kult</strong> sa sjedistem u Sanu Diegu koji su osnovali Applewhite i Nettles 1974., a ciji su svi clanovi 1997. pocini samoubojstvo?",a:["nebeska vrata","heavens gate","heaven's gate"],p:["nebesk","heaven"],e:"Heaven's Gate bio je religijski kult koji je vjerovao da su osnivaci izvanzemaljska bica. 39 clanova pocini ritualno samoubojstvo u ozujku 1997."},
  {n:98,q:"Za koju je nogometnu <strong>reprezentaciju</strong> nastupao trojac Gre-No-Li, zvijezde AC Milana pedesetih?",a:["svedska","sweden","sverige"],p:["svedsk","sweden","sverig"],e:"Gunnar Gren, Gunnar Nordahl i Nils Liedholm — sva troje Svedjani, za AC Milan 1948-1954."},
  {n:99,q:"Nazvan po atickom junaku koji je ubio Minotaura, kako se zove <strong>paradoks</strong> o identitetu objekta kojemu su zamijenjeni svi dijelovi?",a:["tezejev paradoks","paradoks tezejeva broda","ship of theseus"],p:["tezejev","theseus"],e:"Paradoks Tezejeva broda starogricki je filozofski problem o identitetu i kontinuitetu. Postavio ga je Plutarh."},
  {n:100,q:"S ciljem zastite od zmija otrovnica, na Mljet 1910. unesena je zvijer iz koje <strong>porodice</strong> znanstvenog imena Herpestidae?",a:["mungos","mongoose","mungosi"],p:["mungos","mongoos"],e:"Mungos uveden je na Mljet 1910. iz Indije da kontrolira posoke. Bez prirodnih predatora sam je postal invazivna vrsta."},
  {n:101,q:"U kojoj je <strong>macevalackoj disciplini</strong> povrsina pogotka iskljucivo trup, a mora se pogoditi samo vrhom oruzja?",a:["floret","foil"],p:["floret","foil"],e:"Floret je najlaksa macevalacka disciplina. Dopusteni su pogoci samo na trup uz elektronicki sistem bilj pogodaka."},
  {n:102,q:"Slamnat sesir mokorotlo stosastog oblika s cvorom na vrhu nacionalni je simbol i pojavljuje se na zastavi koje <strong>drzave</strong>?",a:["lesoto","lesotho"],p:["lesoto","lesoth"],e:"Lesoto je planinska drzava okruzena Juznom Afrikom. Jedina je drzava cija zastava prikazuje odjecu, a ne oruze ili zivotinju."},
  {n:103,q:"Koja je krupna <strong>pasmina pasa</strong> nazvana po najstarijem gradu u Baden-Württembergu?",a:["rotvajler","rottweiler"],p:["rotv","rottwei"],e:"Rotvajler je nazvana po gradu Rottweilu. Danas je popularna pasmina kao cuvar i radni pas."},
  {n:104,q:"Eurotunnel je vecim dijelom izgraden ispod kojega <strong>prolaza</strong>, najuzeg dijela La Manchea?",a:["doverska vrata","pas de calais","dover strait","dover"],p:["dover","calais"],e:"Doverska vrata (Pas de Calais) najuzi je dio Engleskoga kanala, sirok 34 km. Eurotunnel otvoren je 1994."},
  {n:105,q:"Kako se naziva politicki <strong>dokument</strong> potpisan 3. listopada 1905. u Rijeci, kojim su hrvatski zastupnici podrzali Madarsku u borbi protiv Austrije?",a:["rijecka rezolucija"],p:["rijeck","rezolucij"],e:"Rijecka rezolucija (1905.) kljucni je politicki dokument. Hrvatski zastupnici podrzali su madarsku opoziciju uz uvjet sjedinjenja Dalmacije s Hrvatskom."},
  {n:106,q:"Koji je starogricki <strong>pjesnik</strong> 'bozanskog' imena autor Argonautike, jednog od helenistickih epova sacuvanih do modernog doba?",a:["apolonije rodanin","apollonius of rhodes","apolonije"],p:["apolonej","apolloni"],e:"Apolonije Rodanin (oko 295-215. pr. Kr.) helenisticki je pjesnik. Argonautika epska je poema o Jazonovom pohodu po Zlatno runo."},
  {n:107,q:"Gustavo Dudamel medu ostalim glazbeni je direktor orkestra Simon Bolívar i jedan od najuglednih dirigenata iz koje <strong>drzave</strong>?",a:["venezuela"],p:["venezuel"],e:"Gustavo Dudamel (rod. 1981.) venezuelanski je dirigent. Od 2009. glazbeni je direktor Losandelskog filharmonijskog."},
  {n:108,q:"U kojemu je <strong>stoljecu</strong> nastao Njujorski misal, vazna hrvatskoglagoljski misal pisan u okolici Zadra ili na licko-krbavskom podrucju?",a:["15. stoljece","petnaesto","1400"],p:["15.","1400","cetrn","petna"],e:"Njujorski misal (oko 1400-1410.) jedan je od najljepsih primjeraka hrvatskoglagoljskog pisma. Cuva se u knjiznici Pierpont Morgan."},
  {n:109,q:"U kojemu se <strong>gradu</strong> nalazi Malakološki muzej franjevackog samostana koji je 1963. utemeljio fra Jure Radic?",a:["makarska"],p:[],e:"Makarska je primorski grad u Dalmaciji. Malakološki muzej u franjevackom samostanu jedan je od najvrijednijih te vrste u Europi."},
  {n:110,q:"Kako se kod Zidova zove <strong>obredni rog</strong> u koji se puse na blagdane Ros Hašanu i Jom kipur?",a:["sofar","shofar"],p:["sofar","shofar"],e:"Sofar (shofar) je glazbalo izradjeno od ovnujskog roga, jedan od najstarijih instrumenata u aktivnoj religijskoj upotrebi."},
  {n:111,q:"Nazvan po naslovnom liku romana iz 1851., kako se zove <strong>instrumental</strong> Led Zeppelina s njihovog drugog studijskog albuma?",a:["moby dick"],p:["moby dick"],e:"Moby Dick je instrumental s albuma Led Zeppelin II (1969.). John Bonhamov solo na bubnju trajao je i do 30 minuta na zivim nastupima."},
  {n:112,q:"Buduci da se Jugoslavija nasla izmedju dva bloka, okrenula se uvozu filmova iz koje <strong>latinoamericke drzave</strong>?",a:["meksiko","mexico"],p:["meksik","mexico"],e:"Meksicki film dozivljavao je zlatno doba 1940-ih i 1950-ih. Meksicki vestern i melodrama bili su posebno popularni u Jugoslaviji."},
  {n:113,q:"Nazvan prema vrsti bobicastog voca, koji je naslovni <strong>nadimak</strong> hrabrog porucnika americke konjice Mikea Donovana u hvaljenom vestern-stripu Jean-Michela Charliera?",a:["blueberry"],p:["blueberry","bluberr"],e:"Porucinik Blueberry (1963.) jedan je od najcuvenijih europskih vestern stripova, poznat po realisticnom crtanom stilu Moebiusa."},
  {n:114,q:"Kako se zove <strong>skoljka</strong> poput klina zasiljene ljusture, endem Mediterana, cije je vadjenje strogo zabranjeno u Hrvatskoj?",a:["periska","lostura","pinna nobilis"],p:["perisk","lostur","pinna"],e:"Periska (Pinna nobilis) najveca je endemska skoljka Sredozemnog mora, moze narasti do 1,2 metra. Kriticki je ugrozena vrsta."},
  {n:115,q:"Mimicin, antibiotik namijenjen unistavanju gram-pozitivnih bakterija, imenovan je u cast krojacice iz koje Puccinijeve <strong>opere</strong> praizvedene 1896.?",a:["la boheme","boheme"],p:["bohème","boheme"],e:"La Bohème (1896.) Puccinijeva je opera o mladim artistima u Parizu. Antibiotik Mimicin imenovan je po liku Mimi, bolezljivoj krojacici."},
  {n:116,q:"Prema nizozemskoj rijeci za smedeg medvjeda, tadašnji menader Art Ross dao je nadimak 'Bruins' momcadi NHL-a iz kojega <strong>grada</strong>?",a:["boston"],p:[],e:"Boston Bruins jedan je od originalnih sest momcadi NHL-a, osnovan 1924. Nadimak Bruins dolazi od nizozemske rijeci za medvjeda."},
  {n:117,q:"Koji je talijanski <strong>ekonomist i sociolog</strong> 1897. dosao do zakljucka da 20% stanovnistva posjeduje 80% bogatstva?",a:["vilfredo pareto","pareto"],p:["pareto"],e:"Vilfredo Pareto (1848-1923) otkrio je Paretov princip (pravilo 80/20). Princip se primjenjuje u ekonomiji, managementu i inzenjerstvu."},
  {n:118,q:"Sto je to sto je u ozujku 1966., sedam dana nakon krade, u juznom Londonu pronasao cetverogodisnji pas Pickles?",a:["trofej julesa rimeta","fifa world cup trophy","svjetski kup","jules rimet"],p:["rimet","world cup","trofej"],e:"Trofej Julesa Rimeta ukraden je iz izlozbe u Westminsteru 1966. Pas Pickles pronasao ga je omotanog u novine ispod grma u Norwoodu."},
  {n:119,q:"Umijeće izradbe drvenih tradicijskih djecjih igracaka koje je <strong>hrvatske geografsko-povijesne regije</strong> 2009. upisano na UNESCO-ov popis?",a:["hrvatsko zagorje","zagorje"],p:["zagorje"],e:"Izradba drvenih igracaka iz Hrvatskog zagorja stara je obrtnicka tradicija. Karakteristicne su figurice zivotinja bojene u zivim bojama."},
  {n:120,q:"Pod kojim je cetveroslovnim <strong>akronimom</strong> poznata banka opisana kao 'najkineskija' od svih zapadnih i 'najeuropskija' medu kineskim bankama?",a:["hsbc"],p:[],e:"HSBC (Hongkong and Shanghai Banking Corporation) osnovana je 1865. Danas je jedna od najvecih banaka na svijetu s imovinom od oko 3 bilijuna dolara."},
  {n:121,q:"Kako se, prema zivotinjama koje se u vodi krecu vlastitom snagom, zvao <strong>projekt</strong> u sklopu kojega su se 1960. Walsh i Piccard spustili na dno Marijanske brazde?",a:["nekton"],p:[],e:"Projekt Nekton: Walsh i Piccard spustili su se do dubine 10.916 m u batiskafu Trieste, sto je jos uvijek rekord dubinskog zarona."},
  {n:122,q:"Formalno utemeljenje koje je medunarodne <strong>organizacije</strong> proizaslo iz Urugvajske runde pregovora okoncane u Marakesuu u travnju 1994.?",a:["wto","svjetska trgovinska organizacija","world trade organization"],p:["wto","trgovin","trade organ"],e:"Svjetska trgovinska organizacija (WTO) osnovana je 1995. kao nasljednica GATT-a. Regulira medjunarodnu trgovinu kroz pregovore i rjesavanje sporova."},
  {n:123,q:"Smatran jednim od najvecih jazz-glazbenika u povijesti, koji je legendarni predvodnik jazz fusiona ostavio standarde Spain, 500 Miles High i Armando's Rhumba?",a:["armando anthony chick corea","chick corea","corea"],p:["corea","chick"],e:"Chick Corea (1941-2021) bio je americki jazz pijanist i pioneer jazz fusiona. Osvoji je 23 Grammy nagrade."},
  {n:124,q:"Za kojega se starogrckoga <strong>filozofa</strong>, autora spjevova O prirodi i Ociscenja, veze teorija o cetiri elementa?",a:["empedoklo","empedocles"],p:["empedokl","empedocl"],e:"Empedoklo (oko 490-430. pr. Kr.) uveo je teoriju cetiri elementa: zemlja, voda, vatra i zrak."},
  {n:125,q:"Predstavljajuci borbu izmedju Turaka i Maura, na kojemu se <strong>otoku</strong> od 15. st. svake godine izvodi borbeni ples moreska?",a:["korccula","korcula"],p:["korcul"],e:"Moreska je dramski macevalacki ples koji se izvodi u Korculi od 15. st. Prikazuje sukob krscanskog Mija i turskog Osmana."},
  {n:126,q:"Zicano glazbalo kantela, vrsta citre koja se svira prebiranjem prstiju, tradicionalni je instrument vezan uz koju europsku <strong>drzavu</strong>?",a:["finska","finland","suomi"],p:["finska","finland"],e:"Kantela je finski narodni instrument i nacionalni simbol Finske. Spominje se u finskom narodnom epu Kalevala."},
  {n:127,q:"Francuski kipar André Derain zajedno s Henrijem Matisseom smatra se osnivaccem kojega <strong>umjetnickog pravca</strong>?",a:["fovizam","fauvism"],p:["foviz","fauvis"],e:"Fovizam (1905-1908) karakterizira upotreba isuflih, neklijerhicnih boja. Naziv dolazi od 'fauves' (divlje zvijeri), dali su ga kriticari ironicno."},
  {n:128,q:"Koji je <strong>neo-noir triler</strong> iz 2001. Davida Lyncha proslavio Naomi Watts i bio posljednje filmsko pojavljivanje cuvene Ann Miller?",a:["mulholland drive","bulevar zlocina"],p:["mulholland","bulevar zlocin"],e:"Mulholland Drive (2001.) Davida Lyncha surrealisticki je neo-noir triler o Hollywoodu. Na listi je najvecih filmova svih vremena."},
  {n:129,q:"Minutemen su kao oruzane snage djelovali tijekom kojega osmogodisnjeg <strong>rata</strong>?",a:["americki rat za neovisnost","americki revolucionarni rat","american revolution"],p:["americk","revoluc","neovisn"],e:"Minutemen su bili kolonijalicni dobrovoljci koji su se obvezali biti spremni za boj u minutu. Djelovali su u Americkom revolucionarnom ratu (1775-1783)."},
  {n:130,q:"Peñón de Vélez de la Gomera tvori najkracu drzavnu granicu na svijetu, dugu 85 metara, a razdvaja Spanjolsku od koje <strong>drzave</strong>?",a:["maroko","morocco"],p:["maroko","morocc"],e:"Peñón de Vélez de la Gomera spanjolski je suverenitet na obali Maroka. Njegova 85-metarska granica sluzbeno je najkraca kopnena granica na svijetu."},
  {n:131,q:"Kako se zove <strong>skup podataka</strong> koji se odnose na mjesto i vrijeme tehnicke izradbe publikacije te na fizicke ili pravne osobe koje su u toj izradbi suradivale?",a:["impresum","imprint","impressum"],p:["impresum","impres"],e:"Impresum (lat. impressum) obavezan je element svake publikacije koji sadrzi podatke o nakladniku, tiskari, autoru i godini izdanja."},
  {n:132,q:"Pokrenuta krajem 1995., kako se zvala <strong>internetska trazilica</strong> i prva pretraziva baza podataka cjelovitih tekstova na world wide webu?",a:["alta vista","altavista"],p:["altavista","alta vista"],e:"AltaVista pokrenuta je 1995. i bila je jedna od prvih internetskih trazilica. Google je do 2000. preuzeo primat, a Yahoo! je AltaVistu ugasio 2013."},
  {n:133,q:"Nastala kao posveta omiljenoj marki, pjesma hip-hop grupe Run-DMC u naslovu sadrzi ime kojega <strong>proizvodaca</strong> sportske opreme?",a:["adidas"],p:[],e:"My Adidas (1986.) Run-DMCa bila je prva hip-hop pjesma posvecena brandu. Adidas je 1986. ponudio grupi ugovor od milijun dolara — prvu suradnju hip-hopa i sportskog branda."},
  {n:134,q:"Koje su <strong>dvije boje</strong> na limenom bubnju Oskara Matzeratha?",a:["crvena i bijela","bijela i crvena"],p:["crvena","bijela"],e:"Oskar Matzerath protagonist je romana Limeni bubanj (Die Blechtrommel, 1959.) Güntera Grassa. Crveno-bijeli bubanj simbol je njegovog odbijanja odrasle dobi."},
  {n:135,q:"Njemacka je delegacija 8. studenog 1918. vlakom krenula do sume u blizini kojega <strong>grada</strong> kako bi preuzela prijedloge saveznika za primirje?",a:["compiegne","compiegne"],p:["compiegne","kompjen"],e:"Primirje kojim je zavrssio Primer svjetski rat potpisano je 11. studenog 1918. u vagonima vlaka u sumi Compiègne kraj Pariza."},
  {n:136,q:"Kako se, po Andromedinoj majci i zeni etiopskog kralja Kefeja, naziva <strong>zvijezda</strong> sjevernog neba, cije su najsjajnije zvijezde Cih, Sedir, Kaf i Rukba?",a:["kasiopeja","cassiopeia"],p:["kasiopej","cassiopei"],e:"Kasiopeja je cirkumpolarna zvijezda sjevernog neba, poznata po karakteristicnom W-obliku. U grckoj mitologiji, Kasiopeja je bila etiopska kraljica."},
  {n:137,q:"Zbirka moteta Sacrae cantiones Sibencanina Ivana Lukacica europski je biser glazbe kojega <strong>razdoblja</strong>?",a:["barok","baroque"],p:["barok"],e:"Ivana Lukacic (1587-1648) i Vinko Jelic (1596-1636.) najznacajniji su hrvatski skladatelji baroka. Lukaciceve Sacrae cantiones (1620.) jedan su od najcjenjenijih izvora."},
  {n:138,q:"Od 1945. ideoloski temelj sustava koje je azijske <strong>drzave</strong> Pancasila, filozofija koja pociva na pet glavnih nacela?",a:["indonezija","indonesia"],p:["indonezij","indonesi"],e:"Pancasila je drzavna filozofija Indonezije proglasena 1945. Pet nacela su: vjera u Boga, humanost, jedinstvo, demokratsko vodstvo i socijalna pravda."},
  {n:139,q:"Pod kojim je <strong>imenom</strong> poznatiji Edward Nygma, Batmanov neprijatelj u filmu Batman Forever (1995.) kojega je utjelovio Jim Carrey?",a:["riddler","zagonetkar"],p:["riddler","zagonetk"],e:"Riddler (Edward Nygma) je Batmanov neprijatelj opsjednut zagonetkama, uveden 1948. Jim Carrey dao mu je ekscentrican karakter u Batmanu Forever."},
  {n:140,q:"Koji se sestoslovni <strong>naziv</strong> u antickoj Grckoj koristio za zenu koja obuzeta bozanstvom proorice buducnost?",a:["sibila","sibyl"],p:["sibil","sibyl"],e:"Sibile su bile prorocice u antickom Rimu i Grckoj. Najpoznatija je Krimejska sibila iz Kume u Italiji."},
  {n:141,q:"Uz spanjolski, koji je drugi sluzbeni <strong>jezik</strong> u Paragvaju, ako znamo da taj domorodacki jezik ime dijeli s paragvajskom sluzenom valutom?",a:["guarani"],p:[],e:"Guarani je domorodacki jezik koji govori oko 90% stanovnistva Paragvaja. Jedna je od rijetkih autohtonih americkih jezika na nacionalnoj razini."},
  {n:142,q:"Ukrasen bijelom perjanicom od zdralova, na glavi sinjskih alkara nalazi se kalpak presvucen krznom zivotinje iz kojega <strong>roda</strong> znanstvenog imena Martes?",a:["kuna","marten"],p:["kuna","marten"],e:"Kune (rod Martes) su male zvijeri iz porodice lasica. Krzno kune ima bogatu tradiciju u hrvatskoj kulturi — kuna je bila sredstvo placanja."},
  {n:143,q:"Osnovana 2005., koja je sedmoslovna <strong>platforma</strong> najveca svjetska baza za pretrazivanje i usporedbu cijena hotela?",a:["trivago"],p:[],e:"Trivago je internetska platforma za usporedbu cijena hotela osnovana 2005. u Düsseldorfu. Od 2017. kotira na NASDAQ-u."},
  {n:144,q:"U kojoj je atletskoj <strong>disciplini</strong> Anita Wlodarczyk, smatrana i najboljom svih vremena, cetverostruka svjetska prvakinja i trostruka uzastopna zlatna olimpijka?",a:["bacanje kladiva","hammer throw"],p:["kladiv","hammer"],e:"Anita Wlodarczyk (rod. 1985.) najveca je bacamica kladiva svih vremena s rekordom od 82,98 m (2016.)."},
  {n:145,q:"Imenovano po generalu Unije, kako se zove trenutacno najvislje <strong>stablo</strong> na svijetu, smjesteno u nacionalnom parku Sequoia?",a:["general sherman","sherman"],p:["sherman"],e:"General Sherman je divovski sekvoj u nacionalnom parku Sequoia. S visinom od 84 m i opsegom od 31 m najmasivnije je stablo na svijetu."},
  {n:146,q:"Koji se <strong>dio imenoslovlja</strong> bavi proucavanjem antroponima — osobnih imena, prezimena i nadimaka?",a:["antroponimija","anthroponymy"],p:["antroponim"],e:"Antroponimija je grana onomastike koja proucava osobna imena. Proucava porijeklo, znacenje, raspodjelu i promjenu osobnih imena."},
  {n:147,q:"'Wild Bill' Hickok ubijen je sledom dok je igrao poker drzeci par asova i par osmica u trefu i piku. Kako je nazvana ta <strong>kombinacija</strong> karata u pokeru?",a:["dead man's hand","mrtva ruka"],p:["dead man","mrtva ruka"],e:"Dead Man's Hand (Mrtva ruka) je poker kombinacija para asova i para osmice. Hickok je ubijen 2. kolovoza 1876. u Deadwoodu drzeci te karte."},
  {n:148,q:"Kojom se engleskom stoplenicom naziva <strong>oblik kampiranja</strong> koji ukljucuje luksuzniji smjestaj i bolje dodatne usluge?",a:["glamping"],p:["glamping"],e:"Glamping (glamorous + camping) pojam koji se pojavio oko 2005. Ukljucuje smjestaj u luksuznim satorima, kucicama na drvecu ili jurtkama."},
  {n:149,q:"Smjestena u slijevu srednje Visle, kako se zove najveca i najnaseljenija poljska <strong>provincija</strong>, u kojoj se od 1999. nalazi i glavni grad Varsava?",a:["mazovsko vojvodstvo","mazovia","mazovija"],p:["mazov"],e:"Mazovsko vojvodstvo najvece je od 16 poljskih vojvodstava. Varsava je kulturno, ekonomsko i politicko srediste Poljske."},
  {n:150,q:"Clanovi koje su <strong>dinastije</strong> vladali kao francuski kraljevi izmedju Karolinga i Valois, tocno od 987. do 1328.?",a:["kapetinzi","kapetinci","capet","capetians"],p:["kapet"],e:"Kapetinska dinastija vladala je Francuskom od 987. do 1328. Pod Kapetincima razvila se Francuska kao centralizirana monarhija."},
  {n:151,q:"Koji je jedini Krezin <strong>roman</strong> napisan u prvom licu jednine, iz perspektive neimenanog doktora prava koji osuduje licemjerno gradansko drustvo?",a:["na rubu pameti"],p:["na rubu","rubu pameti"],e:"Na rubu pameti (1938.) jedini je Krezin roman u prvom licu. Smatra se jednim od najvaznijih djela hrvatske modernisticke proze."},
  {n:152,q:"Kako se zvao anticki hispano-rimski <strong>trkac dvokolicama</strong> iz 2. st., koji je u karijeri zaradio oko 35 milijuna sestercija?",a:["gaj apolonije diokle","diokle","gaius appuleius diocles"],p:["diokl"],e:"Gaj Apolonije Diokle (104-146. n. e.) pobijedio je u 1462 od 4257 utrka. Suvremene procjene govore o ekvivalentu od oko 15 milijardi modernih dolara."},
  {n:153,q:"Za otkrice koje su <strong>vrste elektromagnetskog zracenja</strong> Penzias i Wilson 1978. podijelili Nobelovu nagradu za fiziku?",a:["kozmicko mikrovalovno pozadinsko zracenje","cmb","mikrovalovno zracenje","cosmic microwave background"],p:["mikrovalov","cmb"],e:"Kozmicko pozadinsko mikrovalovno zracenje (CMB) otkriveno je slucajno 1965. Predstavlja 'odjek' velikog praska iz ranog svemira."},
  {n:154,q:"Pod kojim je <strong>osobnim imenom</strong> poznat japanski car koji je vladao od 1867. kao Meiji Tenno, ukinuo shogunat i izvrsio upravnu podjelu Japana?",a:["mutsuhito"],p:[],e:"Car Mutsuhito (1852-1912), poznat kao Meiji Tenno (Car prosvjetljenja), transformirao je Japan iz feudalnog drustva u industrijsku veliku silu."},
  {n:155,q:"Kako se zove vrlo suh i topao zimski <strong>vjetar</strong> koji puse iz juzne Sahare i Gvineje noseci prasinu i pijesak do Zelenortskih Otoka?",a:["harmatan","harmattan"],p:["harmatan"],e:"Harmatan je saharski vjetar koji puse prema zapadnoj Africi. Donosi veliku kolicinu prasine, ali i suhocu koja olakšava vrucine."},
  {n:156,q:"Sto je to sto je 1889. na svjetskoj izlozbi u Parizu labinski ucitelj Josip Belusic predstavio kao pretecu danasnjeg tahografa i taksimetra?",a:["velocimetar","velocipedometer","brzinomjer"],p:["velocim","brzinom"],e:"Josip Belusic (1847-1905) patentirao je 1888. velocimetar — uredaj koji je mjerio brzinu i prelu put na biciklima. Prethodnik je modernog tahografa."},
  {n:157,q:"Koristeci samo kamen, zemlju i travu, sto je na danskom jezeru Klejtrup izgradio lokalni farmer Søren Poulsen za tocno 25 godina?",a:["mapu danske","kartu danske","dansku"],p:["danska","mapa"],e:"Søren Poulsen (1890-1941) izgradio je nevjerojatnu topografsku kartu Danske u prirodnoj velicini na jezeru Klejtrup. Povrsina vise od 4000 m2."},
  {n:158,q:"Kako se, po njemackom izrazu za 'zivotni prostor', zvao Hitlerov <strong>koncept</strong> sirenja Treceg Reicha na istocne stepe?",a:["lebensraum","zivotni prostor"],p:["lebensraum","zivotni prostor"],e:"Lebensraum (njem. zivotni prostor) bio je kljucni nacisticki geopoliticki koncept koji je opravdavao osvajanje istocne Europe."},
  {n:159,q:"Koji je televizijski <strong>voditelj i komicar</strong>, dobitnik sest Emmyja, tri desetljeca vodio The Tonight Show (1962-1992.) i pripisuje mu se stvaranje formata kasnonocnog talk showa?",a:["johnny carson","carson"],p:["carson"],e:"Johnny Carson (1925-2005) bio je dominirajuca figura americke kasnonocne televizije gotovo 30 godina. Stvorio je format koji su naslijedili Letterman, Leno i Fallon."},
  {n:160,q:"Koji se talijanski <strong>izraz</strong> koristi za naknadni slikarov ispravak na vec dijelom dovrsenom djelu, cest od Jana van Eycka do Caravaggia i Rembrandta?",a:["pentimento"],p:["pentimento"],e:"Pentimento (tal. kajanje) oznacava naknadne izmjene ispod finalnog sloja boje. Vidljivo je kada gornji slojevi postanu prozirni."},
  {n:161,q:"Kako se zove <strong>franjevac</strong> iz 14. st., roden u Sibeniku, umro muccnickom smrcu u Jeruzalemu, koji je 1970. proglašen prvim od zasad samo tri hrvatska sveca?",a:["nikola tavelic","tavelic"],p:["tavelic"],e:"Nikola Tavelić (oko 1340-1391) sibenski je franjevac koji je mucenicki poginuo u Jeruzalemu 1391. Papa Pavao VI. proglasio ga je svecem 1970."},
  {n:162,q:"Skovan od grckih rijeci za 'dom' i 'znanost', koji je <strong>termin</strong> prvi put 1866. upotrijebio biolog Ernst Haeckel?",a:["ekologija","ecology"],p:["ekologij","ecolog"],e:"Ekologija (grč. oikos — dom + logos — govor) je grana biologije. Ernst Haeckel skovao je termin 1866. u djelu Generelle Morphologie."},
  {n:163,q:"Nazvana po japanskom violinistiu i glazbenom pedagogu, kako se zove <strong>metoda</strong> glazbene edukacije koja polazi od pretpostavke da djeca mogu razviti glazbene vjestine ako su od rodenja okruzena glazbom?",a:["suzuki metoda","suzuki"],p:["suzuki"],e:"Suzuki metoda razvio je Shinichi Suzuki (1898-1998). Djeca usvajaju glazbu na isti nacin kao i jezik — slušanjem i oponasanjem od najranije dobi."},
  {n:164,q:"Albert Bruce Sabin sredinom pedesetih otkrio je cjepivo protiv koje <strong>bolesti</strong> uzrokovane poliovirusom iz skupine enterovirusa?",a:["djecja paraliza","polio","poliomijelitis"],p:["polio","djecja paraliz"],e:"Albert Sabin razvio je oralno cjepivo protiv poliomijelitisa 1955. Zahvaljujuci obima cjepiva, polio je gotovo iskorijenjenn."},
  {n:165,q:"Vjerujuci da oblik nule podsijeca na jaje ove ptice, koji se njezin engleski naziv u kriketu koristi za ispadanje bez trcanja?",a:["duck","patka"],p:["duck"],e:"U kriketu 'duck' (patka) oznacava rezultat 0 za batsmana. Izraz potjece od 'duck's egg' (patkino jaje) jer nula lici na jaje."},
  {n:166,q:"Koji je ruski <strong>autor</strong> djecje literature koji je unutar sezdeset godina tri puta pisao stihove za himnu matine zemlje — za SSSR, a potom za Rusiju?",a:["sergej mihalkov","mihalkov"],p:["mihalkov"],e:"Sergej Mihalkov (1913-2009) jedinstven je u povijesti jer je pisao sluzbene himne trima razlicitim verzijama iste drzave."},
  {n:167,q:"Definirana binarnim logaritmom broja dogadaja, sanon je brojna mjerna jedinica kolicine — <strong>cega</strong>?",a:["informacije","information"],p:["inform"],e:"Shannon (Sh) je mjerna jedinica kolicine informacije, nazvana po Claudeu Shannonu (1916-2001), ocu teorije informacija."},
  {n:168,q:"Kako se zove <strong>disciplina</strong> koja proucava ponasanje zivotinja i ljudi u prirodnim uvjetima, za razliku od biheviorizma koji proucava kontrolirane uvjete?",a:["etologija","ethology"],p:["etologij","etholog"],e:"Etologija je bioloski pristup proucavanju ponasanja u prirodnom okruzenju. Utemeljili su je Tinbergen, Lorenz i von Frisch koji su 1973. dobili Nobelovu nagradu."},
  {n:169,q:"Koje se <strong>kraljevstvo</strong>, cijil je glavni grad bio Petra, prostiralo na podrucju danasnjeg Libanona, Jordana i Sirije od 4. st. pr. Kr. do 106.?",a:["nabatejsko kraljevstvo","nabatejci","nabataea"],p:["nabatej"],e:"Nabatejsko kraljevstvo (oko 4. st. pr. Kr.-106. n. e.) bilo je arapsko kraljevstvo poznato po isklesanom gradu Petri."},
  {n:170,q:"Iako se dugo smatralo da je Alexander Bell izumio telefon, 2002. americki Predstavnicki dom potvrdio je da je pravi <strong>izumitelj</strong> telefona bio koji rodeni Talijan?",a:["antonio meucci","meucci"],p:["meucci"],e:"Antonio Meucci (1808-1889) emigrirao iz Italije i 1860. demonstrirao uredaj za glasovnu komunikaciju. Bell je patentirao slican uredaj 1876."},
  {n:171,q:"Prije solokarijere clan bendova Steeler i Alcatrazz, koji se svedski <strong>gitarist</strong> poznat po heavy metal izvedbama u neoklasicistickom stilu nasao na Timeovoj listi jedanaest najvecih virtuoza?",a:["yngwie malmsteen","malmsteen"],p:["malmsteen","yngwie"],e:"Yngwie Malmsteen (rod. 1963.) svedski je heavy metal gitarist poznat po virtuoznoj tehnici inspiriranoj Paganinijem i Bachom."},
  {n:172,q:"Poznata i kao imperijalna, kako se, po francuskom predsjedniku iz Trece republike, zove najveca zivuca <strong>vrsta zebre</strong>?",a:["grevy zebra","grevyjeva zebra","equus grevyi"],p:["grevy"],e:"Grevyjeva zebra nazvana je po predsjedniku Julesuu Grévyu koji je dobio jednu na dar 1882. Najugrozenija je od tri vrste zebri — preostaje oko 2000 primjeraka."},
  {n:173,q:"Otkrivajuci tajne dugovjecnosti tamossnjih stanovnika, kojom je zajednickom <strong>sintagmom</strong> novinar National Geographica Dan Buettner nazvao pet geografskih podrucja ukljucujuci Sardiniju, Okinawu i Ikariju?",a:["plava zona","blue zone","plave zone"],p:["plava zon","blue zon"],e:"Plave zone (Blue Zones) su podrucja s neobicno visokim udjelom stogodisnjaka. Karakteriziraju ih biljna prehrana, umjerena tjelovjezbazba i jaka socijalna mreza."},
  {n:174,q:"Kazaliste u kojemu je malom <strong>antickom gradu</strong> u Saronskom zaljevu izgradeno u 4. st. pr. Kr. za oko 14.000 gledatelja, a od 1988. je na UNESCO-ovu popisu?",a:["epidaur","epidaurus"],p:["epidaur"],e:"Epidauros anticko je grcko svetiste Asklepija. Kazaliste cuveno je po izvanrednoj akustici — glas s pozornice cuje se do posljednjeg reda bez pojacala."},
  {n:175,q:"Kako se zvala prva hrvatska <strong>radiodrama</strong>, izvedena 1927. na Radio stanici Zagreb, ciji su slušatelji izlazili na balkone misleci da je negdje buknuo pozar?",a:["pozar u operi"],p:["pozar"],e:"Pozar u operi (1927.) bila je prva hrvatska radiodrama. Emitirana je uzivo s efektima koji su bili tako realistini da su slušatelji pomislili na stvarni pozar."},
  {n:176,q:"Nazvana po predsjedniku Ustavnog suda Francuske, kako se zvala arbitrazna <strong>komisija</strong> osnovana 1991. koja je donijela odluku o sukcesiji Hrvatske?",a:["badinterova komisija","badinter komisija"],p:["badinter"],e:"Badinterova komisija osnovana je 1991. po Robertu Badinteru. Donijela je kljucne pravne odluke o sukcesiji drzava bivse Jugoslavije."},
  {n:177,q:"Kako se zove spektakularni <strong>sustav vrtloga</strong> u istoimeoom tjesnacu izmedju otoka Shikokua i Awajija, koji ime dijeli s naslovnim likom iz manga Masashija Kishimota?",a:["naruto","naruto vrtlog"],p:["naruto"],e:"Naruto vrtlozi najpoznatiji su plimni vrtlozi na svijetu, formirani u Naruto tjesnacu. Dostignu promjer do 20 metara. Imenjak su popularnog manga serijala."},
  {n:178,q:"Smješten negde u Hrvatskoj, kako se zove fiktivni rudarski <strong>gradic</strong> prepun misterija u kojemu se odvija radnja istoimene horor racunalne igre istarskog studija Red Martyr?",a:["shadows of doubt","shadows"],p:["shadow"],e:"Red Martyr Entertainment je istarski indie studio koji je razvio horor point-and-click igru smjestenu u fiktivni hrvatski rudarski gradic."},
  {n:179,q:"Kako se zvao svedski <strong>boksac</strong> ciju su mocnu desnicu nazivali 'Thorov malj', koji je 1959. postao svjetski prvak u superteskoj kategoriji pobjedom protiv Floyda Pattersona?",a:["ingemar johansson","johansson","ingo"],p:["johansson","ingo"],e:"Ingemar Johansson (1932-2009) senzacionalno je nokautirao Pattersona 1959. i postal svjetski prvak. Patterson je u remetchu 1960. vratio naslov."},
  {n:180,q:"Od arapskog za 'zeleni otok', kako se zove jedna od najvecih europskih luka i najveci <strong>grad</strong> Gibraltarskog zaljeva?",a:["algeciras"],p:[],e:"Algeciras je grad u juznoj Spaniji s strateškim polozajem nasuprot Gibraltara. Jedna je od najprometnijih luka Mediterana i Atlantika."},
  {n:181,q:"U Drugom svjetskom ratu gotovo potpuno razoren (90% industrijskih objekata), koji je europski <strong>glavni grad</strong> pri poslijeratnoj rekonstrukciji koristio seriju od 22 slike Bernarda Bellotta?",a:["varsava","warsaw","warszawa"],p:["varsav","warsaw","warsza"],e:"Varsava je rekonstruirana gotovo od nule na temelju Bellottovih slika. Stari grad uvrstten je na UNESCO-ov popis svjetske bastine 1980."},
  {n:182,q:"Koju <strong>vitesku titulu</strong> ima Don Pedro iz Mozartova Don Giovannija, a isti naslov je casi i Michael Corleone pri dolasku na Siciliju u trecem dijelu Kuma?",a:["komandatore","commandatore"],p:["komandatore","command"],e:"Commendatore (tal.) je casna titula koja se moze prevesti kao zapovjednik ili vitez komandante. U Don Giovanniju Don Pedro nosi tu titulu."},
  {n:183,q:"Prema araukanskoj rijeci za drvo korišsteno pri dimljenju mesa, kako su se zvali pomorski <strong>pustolovi</strong> koji su u 17. st. napadali spanjolska naselja u Karipskom moru?",a:["bukaniri","bucaneers","buccaneers","buccaneer"],p:["bukanir","buccane"],e:"Bucaneers (bukaniri) su u pocetku bili kolonisti koji su dimili meso. Postali su pirati koji su napadali spanjolske brodove. Tampa Bay Buccaneers NFL tim dobio je ime po piratskon nasljedu."},
  {n:184,q:"Duga oko 200 km, kako se zove <strong>rijeka</strong> koja nastaje spajanjem Eufrata i Tigrisa kod irackog grada Kurne?",a:["satt al-arab","shatt al-arab","arvand"],p:["satt","shatt","arvand"],e:"Satt al-Arab rijeka je duga oko 200 km nastala spajanjem Eufrata i Tigrisa. Oko njene granicne linije bio je uzrok Iracko-iranskog rata (1980-1988)."},
  {n:185,q:"U trenutku koji je predstavljao prvu televizijsku reklamu 1. srpnja 1941., njujorska TV postaja WNBT prekinula je program slikom sata koje <strong>marke</strong>?",a:["bulova"],p:[],e:"Bulova Watch Company platila je 9 dolara za prvu televizijsku reklamu u povijesti, emitiranu 1. srpnja 1941. Trajala je 20 sekundi."},
  {n:186,q:"Kako se zvala <strong>momcad</strong> Formule 1 ciji je vozac bio prvi i jedini osvajac naslova prvaka (1966.) koji je vozio za vlastiti tim?",a:["brabham","brabham racing"],p:["brabham"],e:"Jack Brabham jedini je vozac koji je titulu F1 prvaka osvojio vozeci auto vlastite konstrukcije (1966.)."},
  {n:187,q:"Smatran 'ocem kemijskog ratovanja', koji je Nijemac 1909. otkrio izravnu sintezu amonijaka od dusika i vodika i devet godina kasnije nagraden Nobelovom nagradom?",a:["fritz haber","haber"],p:["haber"],e:"Fritz Haber (1868-1934) otkrio je Haber-Bosch proces sinteze amonijaka koji je omogucio masovnu proizvodnju gnojiva. Isti kemiccar razvio je otrove plinove u Prvom svjetskom ratu."},
  {n:188,q:"Albert Bruce Sabin sredinom pedesetih otkrio je cjepivo protiv koje bolesti uzrokovane poliovirusom?",a:["djecja paraliza","polio","poliomijelitis"],p:["polio","djecja paraliz"],e:"Albert Sabin razvio je oralno cjepivo protiv poliomijelitisa 1955. Polio je danas gotovo iskorjenjenn zahvaljujuci globalnoj vakcinaciji."},
  {n:189,q:"Vjerujuci da oblik nule podsijeca na jaje ove ptice, koji se njezin engleski naziv u kriketu koristi za ispadanje bez ijednog trcanja?",a:["duck","patka"],p:["duck"],e:"U kriketu 'duck' oznacava rezultat 0 za batsmana, jer nula lici na patkino jaje."},
  {n:190,q:"Koji je ruski <strong>autor</strong> djecje literature tri puta pisao stihove za himnu matine zemlje: za SSSR 1943., revidiran 2000. za Rusiju?",a:["sergej mihalkov","mihalkov"],p:["mihalkov"],e:"Sergej Mihalkov (1913-2009) jedinstven je u povijesti jer je pisao sluzbene himne trima razlicitim verzijama iste drzave."},
  {n:191,q:"S najvise biljnih vrsta i najvecim brojem vodozemaca na svijetu, koja velika <strong>drzava</strong> ima najveci svjetski indeks bioraznolikosti (0,85)?",a:["brazil"],p:["brazil"],e:"Brazil je zemlja s najvecom bioraznolikoscu na svijetu — dom Amazonske praprašume koja pokriva 60% teritorija."},
  {n:192,q:"Prve nogometne i teniske utakmice na hrvatskom prostoru, zahvaljujuci engleskim industrijalcima, odigrane su u kojemu <strong>gradu</strong>?",a:["osijek"],p:[],e:"Osijek je bio pionir sporta u Hrvatskoj zahvaljujuci engleskim inzenjerima koji su krajem 19. st. dosli graditi zeljeznicu."},
  {n:193,q:"Americki sociolog Robert Merton skovao je pojam koji je nazvao <strong>cijim efektom</strong>, referirajuci se na dio Prispodobe o talentima: 'Doista, onomu koji ima jos ce se dati'?",a:["matejin efekt","matthew effect"],p:["matejin","matthew"],e:"Matejin efekt (Matthew effect) Robert Merton formulirao je 1968. opisujuci kako vec uspjesni znanstvenici dobivaju vise priznanja za iste doprinose."},
  {n:194,q:"Pod imenom Zmijski otok, ovaj otok povrsine 0,17 km2 do 2009. bio je predmet spora izmedju kojih dviju europskih <strong>drzava</strong>?",a:["ukraine i rumunjska","rumunjska i ukraine","romania and ukraine"],p:["ukrain","rumunj","romani"],e:"Zmijski otok (Zmiinyi) malen je ukrajinansi otok u Crnom moru. ICJ 2009. dosudio je vecinu okolnog akvatorija Rumunjskoj. U veljaci 2022. postao je simbolom ukrajinanskog otpora."},
  {n:195,q:"Pjesmu Oh, What a Beautiful Mornin' na otvaranju kojeg <strong>mjuzikla</strong> Rodgersa i Hammersteina iz 1943. izvodi Curly McLain?",a:["oklahoma","oklahoma!"],p:["oklahom"],e:"Oklahoma! (1943.) revolucionarni je mjuzikl koji je definirao format modernog mjuzikla. Osvoji Posebnu Pulitzerovu nagradu 1944."},
  {n:196,q:"Producenti su uz dopuštenje udruge redatelja umjesto Don Siegela potpisali film kojim <strong>izmisljenim imenom</strong>, koje je do kraja 20. st. korišsteno za redatelje koji odbijaju potpisati film?",a:["alan smithee"],p:["smithee","smith"],e:"Alan Smithee je pseudonim koji su od 1968. do 2000. koristili redatelji koji su se htjeli distancirati od filma."},
  {n:197,q:"Poznata i kao imperijalna, kako se zove najveca zivuca <strong>vrsta zebre</strong> s karakteristicnim prugama i velikim zaobljenim usima koja nastanjuje Keniju i Etiopiju?",a:["grevy zebra","grevyjeva zebra"],p:["grevy"],e:"Grevyjeva zebra najugrozenija je od tri vrste zebri — preostaje svega oko 2000 primjeraka u Keniji i Etiopiji."},
  {n:198,q:"Vladao je od 1867. kao Meiji Tenno, ukinuo shogunat i izvrsio upravnu podjelu Japana na prefekture. Pod kojim je <strong>osobnim imenom</strong> poznat taj japanski car?",a:["mutsuhito"],p:[],e:"Car Mutsuhito (1852-1912) vladao je za iznimno transformativnog perioda. Japan je pretvorio iz feudalnog drustva u industrijsku veliku silu za nekoliko desetljeca."},
  {n:199,q:"Kako se zove vrlo suh i topao zimski <strong>vjetar</strong> koji puse iz juzne Sahare i Gvineje noseci prasinu i pijesak prema Atlantiku?",a:["harmatan","harmattan"],p:["harmatan"],e:"Harmatan puse prema zapadnoj Africi noseci veliku kolicinu prasine. Lokalno ga zovu 'doktorom' jer suši vlagu i olakšava vrucine."},
  {n:200,q:"Koji je oko 800 km dug <strong>hodocasnicki put</strong> Vijece Europe 1987. proglasilo prvom europskom kulturnom rutom?",a:["put svetog jakova","camino de santiago","camino","put sv jakova"],p:["santiago","jakob","camino"],e:"Camino de Santiago vodi do katedrale u Santiagu de Composteli. Danas ga prode vise od 300.000 hodocasnika godisnje."},
  {n:201,q:"Kojim se anglizmom oznacava <strong>najgledaniji televizijski termin</strong>, udarno vrijeme izmedju 19 i 22 sata, kada je pred TV-om najvise gledatelja?",a:["prime time","primetime"],p:[],e:"Prime time (udarni termin) je televizijsko udarno vrijeme od 19 do 22 sata kada je gledanost najvisa. Termin potjece iz americke televizijske industrije 1950-ih."},
  {n:202,q:"Dugovjecni ribar Gregorio Fuentes posluzio kao inspiracija za lik Santiaga u kojemu kratkom <strong>romanu</strong> Hemingwaya?",a:["starac i more","the old man and the sea"],p:["starac","old man"],e:"Starac i more (The Old Man and the Sea, 1952.) kratki je roman Ernesta Hemingwaya koji mu je donio Pulitzerovu nagradu 1953. i pridonio dodjeli Nobelove nagrade 1954."},
  {n:203,q:"Koji je <strong>akronim</strong> simbolizirao uniju rimskog Senata i naroda grada Rima, a sluzbeno se koristio na kovanom novcu i javnim dokumentima?",a:["spqr","senatus populusque romanus"],p:["spqr"],e:"SPQR (Senatus Populusque Romanus — Senat i narod Rima) bio je sluzbeni akronim rimske drzave. Koristio se od Rimske Republike do kasnog Carstva i danas je simbol Rima."},
  {n:204,q:"Na domorodackom jeziku pamon u znacenju 'slap najdubljeg mjesta', pod kojim je <strong>imenom</strong> poznatiji 979 metara visok Kerepakupai Meru, otkriven 1933. u venezuelanskom gorju Auyánu?",a:["anhelov slap","angel falls","slap angela"],p:["anhelov","angel falls"],e:"Anhelov slap (Angel Falls) u Venezueli je najvisi slap na svijetu s visinom pada od 979 m. Ime je dobio po americkom pilotu Jimmieju Angelu koji ga je otkrio iz zraka 1933."},
  {n:205,q:"Koje je <strong>osobno ime</strong> zene, djevojackog prezimena Spencer, koja se u srpnju 1981. udala za Charlesa, princa od Walesa?",a:["diana","lady diana","princeza diana"],p:[],e:"Diana Frances Spencer (1961-1997) udala se za princa Charlesa 1981. Postala je jedna od najpopularnijih i najfotografiranijih osoba na svijetu, poznata kao 'Princeza srca'."},
  {n:206,q:"Ostvarivsi taj podvig izmedju 1989. i 1991., koji je kosarkarski <strong>klub</strong> nakon latvijske Rige jedini osvajao naslov klupskog prvaka Europe triput zaredom?",a:["split","kosarkarski klub split","kk split"],p:["split"],e:"KK Split je hrvatski kosarkarski klub koji je od 1989. do 1991. triput zaredom osvojio naslov prvaka Europe. Bio je dom igraca kao sto su Toni Kukoc i Velimir Perasovic."},
  {n:207,q:"Feritin je globularni protein vazan za unutarstanichno pohranjivanje kojega <strong>kemijskog elementa</strong>?",a:["zelje","fe","iron"],p:["zelj","iron","fe"],e:"Zeljezo (Fe) je kljucni kemijski element za prijenos kisika u krvi i pohranjuje se u tijelu kao feritin. Nedostatak zeljeza najcesci je uzrok anemije."},
  {n:208,q:"Dvije od triju filmskih adaptacija kojega je <strong>stripovskog serijala</strong> Mikea Mignole rezirao Guillermo del Toro, dok je trecu rezirao Neil Marshall?",a:["hellboy"],p:["hellboy"],e:"Hellboy je stripovski lik kojeg je 1993. stvorio Mike Mignola. Del Toro je rezirao Hellboy (2004.) i Hellboy II (2008.), a Neil Marshall Hellboy (2019.)."},
  {n:209,q:"Za kojega se <strong>politicara</strong> i biveg diktatora tvrdi kako su mu ime pod kojim je poznatiji zapravo dali Kinezi skrativsi francuski izraz 'politique potentielle'?",a:["pol pot","polpot"],p:["pol pot"],e:"Pol Pot (1925-1998) bio je voda Crvenih Kmera i kambodski diktator cija je vladavina (1975-1979) dovela do genocida u kojemu je stradalo oko 2 milijuna ljudi."},
  {n:210,q:"Kako se u lingvistici zove <strong>disciplina</strong> koja proucava najmanje jezicne jedinice kojima je pridruzeno znacenje, a ime dijeli s jednom granom biologije?",a:["morfologija","morphology"],p:["morfolog"],e:"Morfologija (grck. morphe — oblik + logos — rijec) je lingvisticka disciplina koja proucava strukturu rijeci i nacine tvorbe novih rijeci. Isti termin koristi se u biologiji za proucavanje oblika organizama."},
  {n:211,q:"Kako se zove jedinstvena medunarodnna <strong>treking-utrka</strong> po ostrom otocnom kamenju i gustom raslinju otoka Pasmana, nazvana po pojmu koji oznacava pukotine u vapnenackim stijenama nastale djelovanjem vode?",a:["karst","karstathon","karst utrka"],p:["karst"],e:"Karst je geoloski fenomen vapnenackih terena s podzemnim sustavima, ponikavama i spiljama. Pasmanski karstathon jedna je od najzahtjevnijih treking-utrka u Hrvatskoj."},
  {n:212,q:"Koji su <strong>tip naselja</strong> 1910. na obali Galilejskog jezera prvi put osnovali zidovski naseljenici nakon sto je izbila svada izmedju clanova jednog poljoprivrednog naselja i postavljenog upravitelja?",a:["kibuc","kibbutz"],p:["kibuc","kibbu"],e:"Kibuc (hebr. kibbutz — skupina) je kolektivna zajednica u Izraelu temeljena na zajednickom vlasnistvu i radu. Pocetkom 21. st. mnogi kibbuci presli su na mjesoviti ekonomski model."},
  {n:213,q:"Od 15. stoljeca, kada ga je prema predaji izmislio kralj Sejong Veliki, hangul je sluzbeno pismo kojega <strong>jezika</strong>?",a:["korejski","korean","korejski jezik"],p:["korejsk","korean"],e:"Hangul je abeceda korejskog jezika s 24 osnovna znaka, jedna od najtocnijih fonetskih pisama na svijetu. Sejong Veliki razvio ga je 1443. kako bi povecao pismenost u Koreji."},
  {n:214,q:"Kako se, prema grckom mitu, zove golemi <strong>kiklop</strong> kojega je Odisej opio i uzarenom mu strelicom spalio oko?",a:["polifem","polyphemus"],p:["polifem","polyphem"],e:"Polifem je sin Posejdona i jednookni div iz Odiseje. Odisej ga je oslijepio kako bi pobjegao iz njegove pecine. Taj cin razbjesnio je Posejdona koji je progonio Odiseja godinama."},
  {n:215,q:"Koja se svjetski poznata <strong>zgrada</strong> nalazi u imenu funk-sastava koji su 1981. osnovala braca Dean i Dino Dvornik?",a:["dioklecijanova palaca","dioklecijan","diocletian palace","palaca"],p:["dioklec","dioclet","palac"],e:"Dioklecijanova palaca u Splitu anticka je palaca izgrajena oko 305. god. za cara Dioklecijana. Braca Dvornik nazvali su bend Dvornici iz Palace."},
  {n:216,q:"Zambra, alegría, farruca i bulería neki su od stilova kojega dinamicnog <strong>plesa</strong>, tradicionalno vezanog uz Andaluziju i pracenog gitarom i kastanjetama?",a:["flamenco"],p:["flamenc"],e:"Flamenco je ples i glazba nastali u Andaluziji, kombinacijom morskih, ciganjskih, arapskih i zidovskih tradicija. UNESCO ga je 2010. uvrstio na Popis nematerijalne kulturne bastine covjecanstva."},
  {n:217,q:"Praizvedena 1892. u koreografiji Mariusa Petipea, pod kojim nam je <strong>naslovom</strong> poznatiji balet Sccelkuncic, neizostavni dio bozicnog kulturnog repertoara?",a:["krcko orasac","the nutcracker","luskacic"],p:["krcko","nutcrack","orasa","luskac"],e:"Krcko orasac (The Nutcracker) je balet Pjotra Iljicha Cajkovskog praizvedena 1892. u Mariinskom teatru u Sankt Peterburgu. Najizvodeniji je balet na svijetu, posebno u bozicno doba."},
  {n:218,q:"Drame Leda i U agoniji dio su ciklusa vezana za zivot koje bogataste aristokratske <strong>obitelji</strong>?",a:["glembajev","glembajevi","glembay"],p:["glemb"],e:"Glembajevi su fiktivna hrvatska aristokratska obitelj iz dramatskog ciklusa Miroslava Krleze. Trilogija (U agoniji, Gospoda Glembajevi, Leda) istrazhuje propadanje gradanske klase."},
  {n:219,q:"Smjesteno u venecijanskom predjelu Cannaregio, kako se zvalo <strong>podrucje</strong> u kojemu su od 1516. bili prisiljeni stanovati lokalni Zidovi, izolirani od ostatka stanovnistva?",a:["geto","ghetto","venetian ghetto"],p:["geto","ghetto"],e:"Venecijansko geto (1516.) bilo je prvo sluzbenooznaceno podrucje prisiljenog stanovanja Zidova u Europi. Naziv 'ghetto' dolazi od talijanskog za ljevaonicu metala koja je tu stajala."},
  {n:220,q:"Koji se cuveni glazbeni <strong>festival</strong> u ljeto 1969. odrzao na farmi Maxa Yasgura u gradiCu Bethelu u saveznoj drzavi New York?",a:["woodstock"],p:["woodstock"],e:"Woodstock Music & Art Fair odrzao se 15-18. kolovoza 1969. Oko 400.000 posjetitelja prisustvovalo je nastupima Jimi Hendrixa, Janis Joplin, The Who i drugih. Simbol je kontrakulture 1960-ih."},
  {n:221,q:"Koju je <strong>igru</strong>, povezujuci vjestinu pisanja rijeci sa sustavom bodovanja, 1933. osmislio americki arhitekt Alfred Butts?",a:["scrabble"],p:["scrabble"],e:"Scrabble je drustvena igra u kojoj igrac postavlja plockice s slovima na ploca tvorenji rijeci. Butts je igru izvorno nazvao Lexico, a Scrabble postaje naziv 1948. Prodana je u vise od 150 milijuna primjeraka."},
  {n:222,q:"Koja je <strong>mjerna jedinica</strong> 1971. dodana kao posljednja, sedma osnovna jedinica sustava SI?",a:["mol","mole"],p:["mol"],e:"Mol (mol) je mjerna jedinica kolicine tvari, dodana sustavu SI 1971. Jedan mol sadrzi tocno 6,022 × 10²³ cestica (Avogadrov broj). Koristi se u kemiji za mjerenje kolicine kemijskih tvari."},
  {n:223,q:"Kako se <strong>preziva</strong> pomorac Lemuel, protagonist i narator romana Jonathana Swifta iz 1726.?",a:["guliver","gulliver"],p:["guliver","gulliv"],e:"Lemuel Guliver protagonist je romana Guliverova putovanja (Gulliver's Travels, 1726.) Jonathana Swifta. Roman je satiricna kritika britanskog drustva kroz fantasticna putovanja."},
  {n:224,q:"Koju <strong>religijsku simboliku</strong> oznacava pet horizontalno polozenih bijelih trokuta (cik-cak oblik), dijeleći bijelu od crvene podloge, na zastavi Bahreina?",a:["islam","pet stupova islama","islamska vjera"],p:["islam"],e:"Pet bijelih trokuta na zastavi Bahreina simboliziraju pet stupova islama. Crvena boja tradicionalna je boja tkanine Kharijita, a bijela boja mira."},
  {n:225,q:"Prema libretu pjesnikinje Alice Goodman, cijenjeni americki skladatelj John Adams u trocincksoj je operi iz 1987. uglazbio fiktivnu nadgradnju povijesnog posjeta kojega americkog <strong>predsjednika</strong> Kini u veljaci 1972.?",a:["richard nixon","nixon"],p:["nixon"],e:"Nixon in China (1987.) opera je Johna Adamsa o povijesnom posjetu predsjednika Nixona Kini 1972. Smatra se jednom od najvaznih americkih opera 20. st."},
  {n:226,q:"Koju <strong>englesku rijec</strong> oznacava slovo H u akronimu VHS, standardiziranom formatu za snimanje i reprodukciju analognih videovrpci?",a:["home","kuca"],p:["home"],e:"VHS (Video Home System) bio je popularni standard za snimanje videosadrzaja na kasete, koji je Sony Betamax pobijedio u 'ratu formata' 1980-ih. Razvio ga je JVC 1976."},
  {n:227,q:"Prekriven muljem i skoljkama, koji je anticki <strong>kip</strong> 1996. pronasao belgijski ronilac Rene Wouters pokraj ototica Vele Orjule, 1,5 km istocno od Losinja?",a:["apoxyomenos","apoksiomen"],p:["apoksiomen","apoxyom"],e:"Apoksiomen (Apoxyomenos) je anticka bronchana skulptura atleta koji struga ulje s tijela, datirana u 2. ili 1. st. pr. Kr. Pronaden je 1996. i izlozen u Muzeju apoksiomena u Malom Losinju."},
  {n:228,q:"Proizasle iz pera Louise May Alcott, pod kojom su naslovnom <strong>sintagmom</strong> poznatije sestre Meg, Jo, Beth i Amy March?",a:["male zene","little women"],p:["male zene","little women"],e:"Male zene (Little Women, 1868-1869.) roman je Louise May Alcott o cetiri sestre u Americi za vrijeme Gradanskog rata. Jedan od najcitanijih romana za djecu i mlade svih vremena."},
  {n:229,q:"Nakon sto je s njom glumio u filmu Imati i nemati, u koju se tada 19-godisnju <strong>glumicu</strong> zaljubio Humphrey Bogart, koja mu je postala cetvrta supruga?",a:["lauren bacall","bacall"],p:["bacall"],e:"Lauren Bacall (1924-2014) upoznala je Bogarta 1944. na snimanju filma To Have and Have Not. Postala je jedna od najvecih holivudskih zvijezda, poznata po niskom i dubokom glasu."},
  {n:230,q:"Muski zbor Shingetsukai s japanskog sveucilista Kwansei Gakuin za svoju je himnu odabrao koju poznatu <strong>ariju</strong> iz opere Nikola Subic Zrinski Ivana pl. Zajca?",a:["u boj u boj"],p:["u boj"],e:"U boj, u boj! je najpoznatija arija iz opere Nikola Subic Zrinski (1876.) Ivana pl. Zajca. Operna arija postala je neformalna hrvatska domoljubna himna."},
  {n:231,q:"Kako se zove <strong>antivirusni program</strong> koji su 1987. kreirali Slovaci Miroslav Trnka i Peter Pasko, ciji akronim znaci Nemocnica na okraji disku?",a:["nod32","eset nod32","eset"],p:["nod32","eset"],e:"NOD32 (Nemocnica na okraji disku — Bolnica na kraju diska) antivirusni je program koji su 1987. razvili slovacki programeri. Kompanija ESET danas je jedan od vodecih proizvodaca cybersecurity softvera."},
  {n:232,q:"Nakon rata za spanjolsko nasljedstvo, Spanjolska je mirom u Utrechtu 1713. Engleskoj prepustila koji <strong>poluotok</strong> — vaznu stratesku tocku Sredozemnoga mora?",a:["gibraltar"],p:["gibraltar"],e:"Gibraltar je britanski prekomorski teritorij na juznom vrhu Iberijskog poluotoka. Strateska vaznost Gibraltarskog tjesnaca kao vrata izmedju Atlantika i Mediterana bila je kljucna za britanski pomorski imperij."},
  {n:233,q:"Ruska federalna jedinica Kalmikija jedina je europska regija u kojoj prevladava koja <strong>religija</strong>?",a:["budizam","buddhism","tibetski budizam"],p:["budiz","buddh"],e:"Kalmikija je ruska republika u kojoj vecina stanovnistva prakticira tibetski budizam. To je jedina pretezito budisticka regija u Europi. Kalmici su potomci mongolskih naroda."},
  {n:234,q:"Kako se zove <strong>hormon</strong> koji luci straznji rezanj hipofize, po kemijskom sastavu polipeptid od devet aminokiselina, koji ima znacajnu ulogu u promicanju socijalnih veza i zove se 'hormonom ljubavi'?",a:["oksitocin","oxytocin"],p:["oksitocin","oxytocin"],e:"Oksitocin je hormon koji je kljucan za stvaranje socijalnih veza, povjerenja i empatije. Luci se pri zagrljajima, rodjenju djece i dojenju. Cesto se naziva hormonom ljubavi ili hormonom grljenja."},
  {n:235,q:"Uz koji se <strong>sport</strong>, cija je krovna organizacija osnovana 1905., vezuju termini snatch i clean and jerk?",a:["dizanje utega","weightlifting","dizanje tezina"],p:["dizanje","weightlif"],e:"Dizanje utega je olimpijski sport s dvije discipline: potisak (snatch) i trzaj (clean and jerk). Medunarodni savez dizacca utega (IWF) osnovan je 1905. u Duanu."},
  {n:236,q:"Koja je <strong>zivotinja</strong> (lat. Monachus monachus), izgledom i veliccinom slicna tuljanu, jedan od najugrozenijih sisavaca u Hrvatskoj?",a:["sredozemna medvjedica","mediteranski tuljan","monah tuljan","monk seal"],p:["medvjedic","monk seal"],e:"Sredozemna medvjedica (Monachus monachus) jedan je od najugrozenijih morskih sisavaca na svijetu. Na Jadranu preostaje svega nekoliko desetaka primjeraka, uglavnom oko otoka."},
  {n:237,q:"Kako se zove <strong>digitalni ljubimac</strong> jajastog oblika kojega su 1996. stvorili Akihiro Yokoi i Aki Maita?",a:["tamagoci","tamagotchi"],p:["tamagoc","tamagotch"],e:"Tamagotchi je elektronska igracka japanskog proizvodaca Bandai. U njoj igrac hranjuje i brine se o virtualnom ljubimcu na malom ekranu. 1997-1998. bila je najprodavanija igracka na svijetu."},
  {n:238,q:"Nadjenuvsi im latinska imena prema visini i obliku, kemiccar i meteorolog amater Luke Howard osmislio je 1803. tablicu za razlikovanje vrsta <strong>cega</strong>?",a:["oblaka","clouds"],p:["oblak","cloud"],e:"Luke Howard (1772-1864) objavio je 1803. tablicu klasifikacije oblaka temeljenu na latinskim nazivima: cumulus, stratus, cirrus i nimbus. Taj sustav, uz male izmjene, koristi se i danas."},
  {n:239,q:"Po kojemu je <strong>cvijetu</strong> poznata revolucija u Tunisu 2011., koja se smatra pocetkom arapskog proljeca?",a:["jasmin","jasmine","revolucija jasmina"],p:["jasmin"],e:"Revolucija jasmina (prosinac 2010. - sijecanj 2011.) bila je narodna revolucija koja je svrgnula predsjednika Ben Alija. Pokrenula je val revolucija poznat kao Arapsko proljece."},
  {n:240,q:"U kojemu se <strong>gradu</strong> zbio dogadaj iz 1397. poznat kao 'krvavi sabor', u kojemu su pristahe kralja Zigmunda sasjekli bana Stjepana Lackovica i hrvatsko plemstvo?",a:["krizevci"],p:["krizevci"],e:"Krvavi sabor u Krizevicima (1397.) bio je event u kojemu su pristahe ugarskog kralja Zigmunda ubili bana Stjepana Lackovica. Dogadaj je oslikao na freski Oton Ivekovic u crkvi u Krizevicima."},
  {n:241,q:"Amália Rodrigues bila je najpoznatija portugalska pjevacica kojega <strong>zanra</strong>, zbog cije je promocije sirom svijeta nazvana njegovom kraljicom?",a:["fado"],p:["fado"],e:"Amália Rodrigues (1920-1999) bila je 'kraljica fada', tradicionalnog portugalskog glazbenog zanra. Fado je 2011. uvrstten na UNESCO-ov Popis nematerijalne kulturne bastine."},
  {n:242,q:"Nagraduivana australska serija Full Frontal parodirala je BBC-jevu djecju <strong>seriju</strong> s cetiri glavna lika koji su zapravo piva omotana australskim etiketama?",a:["teletubbies"],p:["teletu"],e:"Teletubbies je britanska djecja serija BBC-a koja je zapocela 1997. Cetiri sarena lika — Tinky Winky, Dipsy, Laa-Laa i Po — postala su globalni fenomen u ranom odgoju djece."},
  {n:243,q:"Tada jedanaestogodisnjak, koji je slavni <strong>pjevac</strong> 1969. s cetvoricom svoje brace otpjevao jednu od najpoznatijih verzija pjesme Who's Lovin' You?",a:["michael jackson","jackson"],p:["jackson","michael"],e:"Michael Jackson (1958-2009) nastupao je s bratima u The Jackson 5 od 1964. Njihova izvedba Who's Lovin' You 1969. otkrila je nevjerojatni talent jedanaestogodisnjeg Michaela."},
  {n:244,q:"S oko 103 milijuna km2, koja je povrsinom najveca <strong>litosferna ploca</strong> na Zemlji?",a:["pacificka ploca","pacific plate"],p:["pacif"],e:"Pacificka ploca najveca je litosferna ploca s povrsinom oko 103 milijuna km2. Granic s Australskom, Antartickom i Sjevernoamericknom plocom. Siri se od Pacifickog vatrenog pojasa."},
  {n:245,q:"Weihnachts-Stollen, vrsta slatkog kruha, neizostavna je njemacka poslastica koja se tradicionalno priprema u vrijeme kojeg <strong>blagdana</strong>?",a:["bozic","christmas","advent"],p:["bozic","christmas","advent"],e:"Stollen je njemacki bozicni kruh s grozdicama, kandiranim vocem i bademima, presvucen secerom u prahu. Tradicija potjece iz Dresdena u 14. st. Dresdner Stollen je zasticena oznaka."},
  {n:246,q:"Koji je hrvatski muski vaterpolski <strong>klub</strong> LEN proglasio najboljim europskim klubom 20. stoljeca?",a:["vk jadran split","jadran split","jug","vk jug"],p:["jadran","jug"],e:"VK Jug iz Dubrovnika i VK Jadran iz Splita dva su najuspjesnija hrvatska vaterpolo kluba. Jadran Split proglaseni su najboljim europskim klubom 20. st. od strane LEN-a."},
  {n:247,q:"Sastavljen od 411 aminokiselina i djelujuci kao antikoagulans, glikoprotein izoliran iz sline vampirskih sisimasa nazvan je po naslovnom liku kojega gotickog <strong>romana</strong> objavljenog 1897.?",a:["drakula","dracula"],p:["drakul","dracul"],e:"Drakula (Dracula, 1897.) goticni je roman Brama Stokera o vampiru grofu Drakuli. Antikoagulans draculin pronadjen je u slini vampirskog sisimasa i nazvan je prema njemu."},
  {n:248,q:"Koga je Gerard Piqué upoznao uoci svjetskog prvenstva u Juznoj Africi, dok je u Madridu snimala spot za svoju pjesmu Waka Waka?",a:["shakira"],p:["shakira"],e:"Shakira (Shakira Isabel Mebarak Ripoll, rod. 1977.) kolumbijska je pop pjevacica. Njezina pjesma Waka Waka (This Time for Africa) bila je sluzbena pjesma Svjetskog nogometnog prvenstva 2010."},
  {n:249,q:"Nazvan po osobnom imenu protagonistice najpoznatijeg romana Franka Bauma, kako se zove najveci poznati <strong>krater</strong> na Plutonovu mjesecu Haronu?",a:["dorothy","dorothy crater"],p:["dorothy"],e:"Oz (Frank Baum, 1900.) najpoznatiji je roman o Dorothyju Galeu. Krater Dorothy na Charonu (Plutonov mjesec) nazvan je po protagonistici. NASA je 2015. koristila imena iz Oza za obilje kratere."},
  {n:250,q:"Bitka na rijeci Halis 585. pr. Kr. izmedju Medijskog Carstva i Lidije naglo je prekinuta zahvaljujuci kojoj <strong>astronomskoj pojavi</strong>?",a:["pomrcina sunca","solarna eklipsa","eclipse"],p:["pomrcin","eclipse","eklips"],e:"Pomrcina Sunca 28. svibnja 585. pr. Kr. prekinula je bitku izmedju Medijaca i Lidijaca. Obje strane su je protumacile kao bozanski znak i sklopile mir. Talesova predikcija ove pomrcine jedna je od prvih zabilezenih u povijesti."},
  {n:251,q:"Marku Gabiju Apiciju pripisuje se glasoviti spis De re coquinaria Romae Augustae, a smatra se prvom pravom kakvom <strong>vrstom knjige</strong> u zapadnom svijetu?",a:["kuharica","cookbook","kuharska knjiga"],p:["kuharic","cookbook"],e:"De re coquinaria (O kuhanju) rimska je zbirka recepata iz 4. ili 5. st. n. e. Smatra se najstarijim sacuvanim kuharicom zapadnog civilizacijskog kruga."},
  {n:252,q:"U doslovnom znacenju 'lutajuca osoba', koji je <strong>naziv</strong> za samuraja bez gospodara u feudalnom Japanu, a ime dijeli s filmom Johna Frankenheimera iz 1998.?",a:["ronin"],p:["ronin"],e:"Ronin je samuraja koji je ostao bez feudalnog gospodara (daimyo) zbog njegove smrti ili izgnanstva. Film Ronin (1998.) s Robertom De Nirom bavi se skupinom najamnih vojnika."},
  {n:253,q:"Trash metal-bend Slayer objavio je 1986. album Reign in Blood koji otvara pjesma Angel of Death, inspirirana kojim zloglasnim nacistickim <strong>lijecnikom</strong>?",a:["josef mengele","mengele"],p:["mengele"],e:"Josef Mengele (1911-1979), poznat kao 'Andjeo smrti', bio je nacisticki lijecnik koji je provodio nadasve okrutne eksperimente na zatvocenicima u Auschwitzu."},
  {n:254,q:"Dijeleći ime s urotnikom protiv Julija Cezara, kako se zove <strong>pjenusac</strong> koji sadrzi manje od 15 g/l neprovrela sladora?",a:["brut","brut champagne","brut prosecco"],p:["brut"],e:"Brut je oznaka za suhe pjenusace i sampanjce s manje od 15 g/l rezidualnog secera. Naziv 'Brut' potjece od rimskog Luciusa Junija Bruta, jednog od osnivaca Rimske Republike."},
  {n:255,q:"Koji je izmisljeni <strong>jezik</strong> lingvist Marc Okrand opisao u knjizi skracena naslova TKD, temeljen na zvukovima i rijecima za film Star Trek: The Motion Picture?",a:["klingonski","klingon"],p:["klingon"],e:"Klingonski jezik (tlhIngan Hol) stvorio je lingvist Marc Okrand za filmsku seriju Star Trek. Danas ga govori oko 20-30 fluent govornika, a preveden je Hamlet i dijelovi Biblije."},
  {n:256,q:"Prema arapskom za 'tumaciti', tefsir je disciplina koja se bavi tumacenjem izravno prenesene Bozje rijeci u kojoj <strong>svetoj knjizi</strong>?",a:["kuran","quran","koran"],p:["kuran","quran","koran"],e:"Tefsir je islamska disciplina egzegeze Kur'ana. Kur'an (arap. al-Quran — Citanje) sveta je knjiga islama, objavljena proroku Muhamedu u 7. st. n. e."},
  {n:257,q:"Remek-djelo Diega Velasqueza iz 1656. Male dvorske dame (Las Meninas) cuva se u kojemu poznatom <strong>muzeju</strong>?",a:["muzej prado","prado"],p:["prado"],e:"Muzej Prado u Madridu jedan je od najvecih i najvaznih likovnih muzeja na svijetu. Las Meninas Velasqueza smatra se jednom od najkompleksnijih i najfascinantnijih slika u zapadnoj umjetnosti."},
  {n:258,q:"S podnaslovom Epizoda u zivotu umjetnika, kakva je naslovna simfonija Hectora Berlioza iz 1830. godine, koju je Leonard Bernstein opisao kao prvi glazbeni izlet u psihodeliju?",a:["fantasticna","fantastic symphony","fantastique"],p:["fantast","fantaziozn"],e:"Fantasticna simfonija (Symphonie fantastique, 1830.) Hectora Berlioza programska je simfonija koja opisuje ljubavnu opsesiju. Revolucionarna je po upotrebi idee fixe i po boji orkestra."},
  {n:259,q:"Nakon sto je 1747. ujedinio nekoliko pastuonskih plemena i postavio Kandahar za glavni grad, Ahmad sah Durrani smatra se osnivaccem koje moderne <strong>drzave</strong>?",a:["afganistan","afghanistan"],p:["afgani","afghan"],e:"Ahmad sah Durrani (1723-1773) osnivac je Afganistana i smatra se 'ocem afganistanskog naroda'. Njegov emirat bio je jedna od najvecih islamskih sila 18. st."},
  {n:260,q:"Po kojemu je plesu i glazbenom <strong>zanru</strong> nazvan efekt koji je 1999. izazvao gotovo 35-postotni pad vrijednosti brazilskog reala, uzrokovan azijskom financijskom krizom?",a:["samba","samba efekt"],p:["samba"],e:"Samba efekt opisuje kako je azijska financijska kriza 1997. prenijela svoju zarazu na brazilsku ekonomiju 1999. i uzrokovala 35% devalvaciju reala."},
  {n:261,q:"Kako bi podigao moral zaposlenika osiguravajuceg drustva, koji je <strong>simbol</strong> izrazavanja osjecaja i psihickih stanja u pisanoj komunikaciji 1963. kreirao graficki umjetnik Harvey Ross Ball?",a:["smajlic","smiley face","smiley"],p:["smajl","smiley"],e:"Smajlic (Smiley Face) Harvey Ross Balla postao je jedan od najprepoznatljivijih simbola u povijesti. Ball je primio samo 45 dolara za lik i nikad ga nije zastitio autorskim pravom."},
  {n:262,q:"Tko ili sto je posjetilac iz slavne pjesme Edgara Allana Poea Gavran, objavljene 1845.?",a:["gavran","the raven","raven"],p:["gavran","raven"],e:"Gavran (The Raven, 1845.) Edgara Allana Poea jedna je od najcuvenijih americkih pjesma. Gavran koji ponavlja 'Nevermore' simbol je neizljecive tuge i gubitka."},
  {n:263,q:"Kako se zvalo ilirsko <strong>pleme</strong> nastanjeno u isttocnom donjem porjecju Neretve, cije se glavno srediste nalazilo u Osanicicma kraj Stoca?",a:["daorsi","daorson"],p:["daors"],e:"Daorsi su bili ilirsko pleme koje je zivjelo u dolini Neretve. Koristili su grexkke kulturne elemente i kovali novac s natpisom DAORSŌN."},
  {n:264,q:"Ime koje je <strong>pokrajine</strong> u sredisnjemu dijelu Peloponeza postalo sinonim za idilichan seoski zivot, a nalazi se i u naslovu pastoralnog romana Jacopa Sannazara?",a:["arkadija","arcadia"],p:["arkad","arcad"],e:"Arkadija je pokrajina u Grckoj koja je u anticko doba sluzila kao simbol idilichnog, pastirskog zivota. Jacopo Sannazaro je 1504. objavio utjecajni pastoralni roman Arcadia."},
  {n:265,q:"Adrian Panatta jedini je tenisac koji je na Roland Garrosu pobijedio kojeg Svedjanina i sestterostrukog osvajaca toga Grand Slama?",a:["bjorn borg","borg"],p:["borg"],e:"Bjorn Borg (rod. 1956.) dominirao je Roland Garrosom od 1974. do 1981., osvajajuci ga 6 puta. Adrian Panatta jedini mu je protivnik koji ga je pobijedio na tom turniru (1973.)."},
  {n:266,q:"Nakon sto ga je u filmu popularizirao Tom Cruise, prodaja kojeg je <strong>modela</strong> suncanih naocala Ray-Ban 1986. porasla za oko 40 posto?",a:["aviator","ray-ban aviator"],p:["aviator"],e:"Ray-Ban Aviator model je suncanih naocala koji je nosio Tom Cruise u Top Gunu (1986.). Prodaja je porasla za 40% nakon filma. Aviator je izvorno dizajniran za americke vojne pilote 1930-ih."},
  {n:267,q:"Kako se zove <strong>podrucje psihologije</strong> koje se bavi pretezito spoznajnim procesima te procesima kojima se stjece znanje i rjesavaju problemi, kao i percepcijom, pamcenjem i govorom?",a:["kognitivna psihologija","cognitive psychology"],p:["kognit","cogniti"],e:"Kognitivna psihologija proucava mentalne procese kao sto su percepcija, pamcenje, jezicno razumijevanje i rjesavanje problema. Razvila se kao disciplina 1950-1960-ih."},
  {n:268,q:"Pod znanstvenim nazivom Spilocaea oleagina, paunovo oko poznato je po karakteristicnim okruglastim, zutim pjegama i najopasnija je bolest lisca koje mediteranske <strong>biljke</strong>?",a:["maslina","olive","maslinovo stablo"],p:["maslin","olive"],e:"Paunovo oko masline (Spilocaea oleagina) najopasnija je gljicna bolest maslinova lista. Maslinogorstvo je kljucna grana mediteranske poljoprivrede, a Hrvatska je poznata po kvalitetnim maslinovim uljima."},
  {n:269,q:"Iako mnoge asocira na sport, koji je Volkswagenov <strong>model</strong> automobila ipak nazvan prema toploj struji sjevernog Atlantskog oceana?",a:["golf","volkswagen golf"],p:["golf"],e:"Volkswagen Golf nazvan je prema Golfskoj struji (Gulf Stream), a ne prema sportu golfu. Od svog lansiranja 1974. jedan je od najprodavanijih automobila u Europi."},
  {n:270,q:"Indijska savezna drzava Kerala postala je 1957. prvo podrucje na svijetu u kojemu je na slobodnim demokratskim izborima vlast formirala koja politicka <strong>stranka</strong>?",a:["komunisticka partija","komunisti","communist party","cpi"],p:["komunist","communist"],e:"Kerala je 1957. postala prva drzava na svijetu koja je demokratskim izborima izabrala komunisticku vladu. Kerala je i danas poznata po visokoj pismenosti i kljucanim socijalnim postignucima."},
  {n:271,q:"Dokumentarni film Johna Scheinfelda U potrazi za Traneom (Chasing Trane) usredotocen je na zivot i glazbu kojega cuvenog <strong>dzezista</strong>?",a:["john coltrane","coltrane"],p:["coltrane"],e:"John Coltrane (1926-1967) jedan je od najutjecajnijih jazz glazbenika. Poznat po inovativnoj tehnici 'sheets of sound' i albumima kao sto su A Love Supreme i Giant Steps."},
  {n:272,q:"Po kojemu je <strong>glodavcu</strong> iz porodice Sciuridae nazvana biblioteka (1957.-1998.) izdavacke kuce Mladost, koja je bila sredisnji medij djecje knjizevnosti?",a:["vjeverica","squirrel"],p:["vjesveri","squirr"],e:"Vjeverica je bila serija djecjih knjiga izdavacke kuce Mladost iz Zagreba, pokrenuta 1957. Obuhvacala je stotine naslova domacih i stranih pisaca i oblikovala generacije citatelja."},
  {n:273,q:"Uzrokujuci gubitak cakline na zubima i osjetljivost zvacnih misica, sto tocno u stomatologiji oznacava pojam bruksizam?",a:["skripanje zubima","stiskanje zuba","bruxism","grizenje zuba"],p:["skrip","stisk","brug"],e:"Bruksizam je nesvjesno skripanje ili stiskanje zuba, najcesce za spavanja. Uzrokuje trosenje cakline, bolove u celjusti i glavobolje. Tretira se udlagama i tehnkama relaksacije."},
  {n:274,q:"Koji se antropomorfni <strong>zabac</strong> prvi put pojavio 2005. kao jedno od cetiriju tinejdzerskih cudovista u seriji stripova Matta Furieja Boy's Club?",a:["pepe zaba","pepe the frog","pepe"],p:["pepe"],e:"Pepe the Frog stvorio je Matt Furie 2005. Postao je jedan od najrasirejenijih internetskih memova, a Furie se godinama borio s njegovim prisvajanjem od strane ekstremnih grupa."},
  {n:275,q:"Zapise predavanja filozofa Plotina skupio je i objavio pod nazivom Eneade, podijelivsi ih u sest knjiga od kojih je svaka sastavljena od koliko <strong>dijelova</strong>?",a:["devet","9"],p:["devet","nine","9"],e:"Eneade (grck. ennea — devet) je zbirka spisa neoplatonistickog filozofa Plotina (205-270.). Svaka od sest knjiga sadrzi devet traktata, sto ukupno cini 54 rasprave."},
  {n:276,q:"Koji je <strong>slikar</strong> nadahnut ruskim puckim legendama i folklorom, opsjednut provincijskim zidovskim okolisem iz djetinjstva u Vitebsku, stvarao u ozracju kubizma, ekspresionizma i nadrealizma?",a:["marc chagall","chagall"],p:["chagall"],e:"Marc Chagall (1887-1985) bio je rusko-francuski slikar koji je bio poznat po fantasticnim, snovidnim scenama inspiriranim zidovskim folklorom i zivotom. Jedan je od najprepoznatljivijih modernista."},
  {n:277,q:"U pismu Robertu Hookeu 1675., Newton je napisao cuvenuu recenicu o stajanju na ramenima <strong>koga</strong>?",a:["divova","giants","dzinova"],p:["divov","giant","dzinov"],e:"Newtonova izreka 'Ako sam vidio dalje od drugih, to je zato sto sam stajao na ramenima divova' izrazava vaznost prethodnih dostignuca u znanosti. Slicne izreke koristili su i drugi autori prije Newtona."},
  {n:278,q:"Americki blues i jazz soul-glazbenik Jimmy McGriff primarno je svirao koji veliki glazbeni <strong>instrument</strong>?",a:["orgulje","organ","hammond orgulje"],p:["orgulj","organ"],e:"Jimmy McGriff (1936-2008) bio je americki jazz i soul glazbenik poznat po sviranju Hammond B-3 orgulja. Poznat je po instrumentalnoj verziji pjesme Raya Charlesa I've Got a Woman."},
  {n:279,q:"Kakav je <strong>tango</strong> u naslovu romana iz 1985., kojim je Laszló Krasznahorkai usao u vrh madarske knjizevnosti?",a:["satanski","sátántangó","sotona tango"],p:["satansk","satan"],e:"Sátántangó (1985.) prvi je roman Laszló Krasznahorkaia, jednog od najznacajnijih suvremenih europskih pisaca. Bela Tarr je 1994. snimio istoimeni film od 7,5 sati."},
  {n:280,q:"Po kojemu je srednjovjekovnom <strong>vladaru</strong> nazvana prestizna nagrada za rad na europskom jedinstvu, koju od 1950. dodjeljuje grad Aachen?",a:["karlo veliki","charlemagne"],p:["karlo","charlem"],e:"Nagrada Karla Velikog (Karlspreis) dodjeljuje se od 1950. u Aachenu osobama koje su se istakle u promicanju europskog jedinstva. Nazvana je po Karlu Velikom, prvom vladaru objedinjene zapadne Europe."},
  {n:281,q:"Najniza (-105 m) i najvisa (6961 m) tocka obiju Amerika nalaze se u kojoj <strong>drzavi</strong>, ukupno petoj po broju stanovnika na oba kontinenta?",a:["argentina"],p:["argentin"],e:"Argentina je zemlja s najvecom visinskon razlikon ikad: Laguna del Carbon (-105 m) i Aconcagua (6961 m). Peta je po broju stanovnika u Amerikama s oko 45 milijuna."},
  {n:282,q:"Koju su mobilnu <strong>aplikaciju</strong> za slanje teksta i multimedija 2013. pokrenula braca Nikolaj i Pavel Durov, poznati i kao osnivaci drustvene mreze VKontakte?",a:["telegram"],p:["telegram"],e:"Telegram je aplikacija za slanje poruka pokrenuta 2013. Poznata je po snaznoj enkripciji i privatnosti. Osnivaci Pavel i Nikolaj Durov ranije su osnovali rusku drustevnu mrezu VKontakte."},
  {n:283,q:"<strong>Tko</strong> je od 1951. do 1960. drzao naslov boksackog prvaka Ugande u poluteskoj kategoriji?",a:["idi amin","idi amin dada"],p:["idi amin"],e:"Idi Amin (1925-2003) bio je ugandski vojnik koji je 1951-1960. bio boksacki prvak Ugande u poluteskoj kategoriji. Kao predsjednik Ugande (1971-1979.) proveo je krvavu diktaturu."},
  {n:284,q:"Kasniji sukob u tanzanijskom Nacionalnom parku Gombe, koji je trajao od 1974. do 1978., poznat je kao rat kojih <strong>vrsta primata</strong>?",a:["cimpanze","chimpanzees","chimpanzee war"],p:["cimpanz","chimpanz"],e:"Rat cimpanza u Gombeu (1974-1978.) promatrala je Jane Goodall. To je jedini dokumentirani slucaj organiziranog rata medu necovjekolikim primatima."},
  {n:285,q:"Koje je <strong>ime</strong> naslovne Disneyeve ratnice, javnosti prvi put predstavljene 1998., na mandarinskom znaci 'magnolija'?",a:["mulan"],p:["mulan"],e:"Mulan je Disneyjev animirani film iz 1998. temeljen na kineskoj legendi o Hua Mulan. Na kineskom 'mulan' znaci magnolija. Film je 2020. dobio live-action remake."},
  {n:286,q:"Sestominutna pjesma Paranoid Android kojeg je britanskog <strong>rock-benda</strong>, s njihovog treceg studijskog albuma OK Computer iz 1997., nazvana po liku iz Adamsove trilogije Vodic kroz galaksiju za autostopere?",a:["radiohead"],p:["radiohead"],e:"Radiohead je britanski rock bend koji je 1997. objavio album OK Computer, jedan od najutjecajnijih albuma 1990-ih. Paranoid Android nazvana je po Marvinu, depresivnom androidu iz Adamsove serije."},
  {n:287,q:"Od grckih rijeci za 'povratak' i 'patnju', koji bi se <strong>osjecaj</strong> mogao opisati kao patnja uzrokovana neutazenom zudnjom za povratkom?",a:["nostalgija","nostalgia"],p:["nostalgij","nostalgi"],e:"Nostalgija (grck. nostos — povratak + algos — bol) termin je skovao fiziccar Johannes Hofer 1688. za dijagnozu svicarskih vojnika. Danas oznacava ceznju za prolim vremenima."},
  {n:288,q:"Koji je rasterski <strong>graficki uredzivac</strong> ukljucen u sve verzije sustava Microsoft Windows od 1985.?",a:["paint","ms paint","microsoft paint"],p:["paint"],e:"Paint (Microsoft Paint) besplatni je rasterski graficki uredzivac koji prati Windows od 1985. Osnovna alatka za uredivanje slika u Windows okruzenju."},
  {n:289,q:"Dijeleci ime sa sveukupnoscu kemijskih reakcija u organizmu, kako se zvao arhitektonski <strong>pokret</strong> u Japanu nakon Drugoga svjetskog rata koji je planirao izgradnju arhitektonskih megastruktura?",a:["metabolizam","metabolism"],p:["metaboliz"],e:"Metabolizam je japanski arhitektonski pokret 1950-60-ih koji je zamis ljao gradove kao biloske organizme koji rastu i mijenjaju se. Kenzo Tange bio je kljucni pobornik."},
  {n:290,q:"Nagraden sa sedam Oscara, koji povijesni <strong>spektakl</strong> Davida Leana ne bi dobro prosao na Bechdel testu jer u vise od tri i pol sata filma nema niti jedan zenski lik s izgovorenim tekstom?",a:["lawrence od arabije","lawrence of arabia"],p:["lawrence"],e:"Lawrence od Arabije (1962.) Davida Leana osvoji 7 Oscara ukljucujuci za Najbolji film. Peter O'Toole utjelovio je T. E. Lawrencea u ovom epskom povijesnom spektaklu bez zenskaih likova s dijalogom."},
  {n:291,q:"Nazvan 'Covjekom s jezera Mungo', pradavni lovac ciji su pronadeni ostaci stari oko 42 tisuce godina smatra se najstarijim pripadnikom Homo sapiensa na kojemu <strong>kontinentu</strong>?",a:["australija","australia"],p:["australij","australi"],e:"Mungo Man pronadjen je 1974. u jezernom podrucju Mungo u Novom Juznom Walesu, Australija. Oko 42.000 godina star i dokazuje raniji doseljaje modernih ljudi u Australiju nego sto se mislilo."},
  {n:292,q:"U arapskim zemljama tradicionalno se prorice iz manje kolicine koje <strong>tekucine</strong> koja se ulije u dlan i po nacinu razlijevanja moze tumaciti necija narav i buducnost?",a:["kava","coffee"],p:["kava","coff"],e:"Citatanje iz taloga kave (tasseography) je oblik gatanja rasprostranjen u arapskim i mediteranskim kulturama. Kava se pije, a talog na dnu salice tumaci se za predvidanje buducnosti."},
  {n:293,q:"U kojemu <strong>sportu</strong> Aladára Gerevicha smatraju najvecim olimpijcem u povijesti, koji je jedini sportasc koji je u istoj disciplini osvojio sest zlatnih medalja, a ujedno je osvajac zlata u najvecemu rasponu Igara (1932. i 1960.)?",a:["macedevanje","fencing","sablja"],p:["macevanj","fencing","sabl"],e:"Aladár Gerevich (1910-1991) madjarski je macevatelj koji je osvoji 7 olimpijskih zlatnih medalja (6 u ekipnoj sabljaci). Nastupio je na 6 uzastopnih Olimpijada od 1932. do 1960."},
  {n:294,q:"Kako se, dvjema latinskim rijecima, zovu <strong>istrazivacki eksperimenti</strong> u kojima se efekti razlicitih bioloskih entiteta testiraju na cijelim zivim organizmima?",a:["in vivo"],p:["in vivo"],e:"In vivo (lat. u zivomu) istrazivanja su eksperimenti koji se provode na cijelim organizmima, za razliku od in vitro testiranja u laboratorijskim uvjetima."},
  {n:295,q:"Hrvatski botaniccar i akademik Ivo Pevalek zasluzeno je da se osnuje koji <strong>nacionalni park</strong> koji je zahvaljujuci njemu dobio nacionalnu i svjetsku zastitu?",a:["plitviicka jezera","plitvice","plitvicka jezera"],p:["plitvic"],e:"Plitvicka jezera proglasena su nacionalnim parkom 1949., uvelike zahvaljujuci radu botanicara Ive Pevaleka. UNESCO ih je 1979. uvrstio na Popis svjetske kulturne i prirodne bastine."},
  {n:296,q:"Koje je <strong>ime</strong>, ciji je izvorni oblik Sungmanitu Tháŋka Ób Wačhí, nadjenuli Indijanci plemena Sioux poruciniku Unije Johnu J. Dunbaru u nagraduivanom vesternu Kevina Costnera iz 1990.?",a:["plese s vukovima","dances with wolves"],p:["plese s vuk","dances with wolf"],e:"Ples s vukovima (Dances with Wolves, 1990.) americki je western filma Kevina Costnera koji govori o poruciniku koji se priblizi plemienu Sioux. Osvoji 7 Oscara ukljucujuci za Najbolji film."},
  {n:297,q:"Kojega <strong>sveca</strong> i prvog biskupa Liegeea legende opisuju kao lovca kojega je obratio jelen s krizem medu rogovima?",a:["sveti hubert","hubert"],p:["hubert"],e:"Sveti Hubert (656-727) pricuvajnik je lovaca, opticiara i matematicara. Legenda kaze da je obratio mladi lovac koji je ugledao jelena s krizem medu rogovima. Slavi se 3. studenog."},
  {n:298,q:"U kojemu je <strong>desetljecu</strong> 20. stoljeca Jim Hines postao prvi sprinter koji je pretrccao 100 metara za manje deset sekundi?",a:["sezdesete","1960s","60-ih","60-te"],p:["sezdeset","1960","60-ih"],e:"Jim Hines (rod. 1946.) 14. listopada 1968. u Mexico Cityju postao je prvi sprinter koji je 100 m pretrccao za manje od 10 sekundi — tocno 9,95 s. To je bio jedan od kljucnih trenutaka u atletici."},
  {n:299,q:"Koji je <strong>zajednicki naziv</strong> za sest spojenih i jedno odvojeno jezero na jugu Hrvatske, redom Ocusa, Trnisevo, Podgora, Sladinac, Vranjak, Sipak i Plitko jezero?",a:["imotska jezera","imotski","modro i crveno jezero"],p:["imotsk"],e:"Imotska jezera sedam su prirodnih jezera na Imotskoj krajini, nastala u krstkim ponikavama. Najpoznatija su Modro jezero i Crveno jezero koja su turisticke atrakcije."},
  {n:300,q:"Kako se prezivao austrijski <strong>pedijatar</strong> Johann koji je 1944. opisao djecu koja imaju normalnu inteligenciju, ali im nedostaje vjestina neverbalne komunikacije, fizicki su nespretna i ne pokazuju empatiju?",a:["asperger"],p:["asperger"],e:"Hans Asperger (1906-1980) austrijiasnki je pedijatar koji je 1944. opisao stanje koje danas zovemo Aspergerov sindrom, visokofunkcionalni oblik autisticnog spektra. Sindrom je unistuen u DSM-5 u kategoriju autisticnog spektra."},
  {n:301,q:"Na jugu koje se <strong>drzave</strong> nalazi atraktivna, 80-ak metara duboka klisura Partnachklamm, koja je glumila transilvanijski prolaz Borgo u filmu Nosferatu: Fantom noci iz 1979.?",a:["njemacka","germany","deutschland"],p:["njemack","german"],e:"Partnachklamm je gorska klisura blizu Garmisch-Partenkirchena u Bavarskoj, Njemacka. Film Nosferatu: Fantom noci (1979.) W. Herzoga koristio je bavarske lokacije za transilvanijsku atmosferu."},
  {n:302,q:"<strong>Tko</strong> je ranom primjenom daktiloskopije 1892. uspio pronaci odgovornu osobu za dvostruko ubojstvo djece u slucaju Francisce Rojas?",a:["juan vucetich","vucetich","juan vucetic"],p:["vucetich","vucetic"],e:"Juan Vucetich (1858-1925) bio je argentinski kriminolog, roden u Hvaru, koji je 1892. razvio prvu prakticnu metodu identifikacije otisaka prstiju i time rijesio prvi slucaj ubojstva ovom metodom."},
  {n:303,q:"Iz ustaljenog naziva slike Vjekoslava Karasa nastale izmedju 1845. i 1847. doznajemo da je rijec o kojemu zichanom <strong>instrumentu</strong>?",a:["gitara","guitar"],p:["giitar","guitar"],e:"Vjekoslav Karas (1821-1858) bio je prvi profesionalni hrvatski slikar skolovan u inozemstvu. Njegova Rimljanka s gitarom (oko 1845.) smatra se jednom od najljepsih hrvatska portretnih slika."},
  {n:304,q:"Utemeljen u Parizu 2010., najznacajniji europski festival TV serija Series Mania od 2018. premijerno prikazuje najvaznije svjetske serije u kojemu sjevernofrancuskom <strong>gradu</strong>?",a:["lil","lille"],p:["lil","lille"],e:"Lille je grad na sjeveru Francuske blizu belgijske granice. Series Mania festival je od 2018. smjesten u Lilleu i jedan je od najvaznih festivala televizijskih serija u Europi."},
  {n:305,q:"Terminom kojim je Gertrude Stein opisala americke pisce koji su zivjeli u Parizu dvadesetih, kako se uobicajeno naziva <strong>generacija</strong> koja se borila u Prvom svjetskom ratu, rodena izmedju 1883. i 1900.?",a:["izgubljena generacija","lost generation"],p:["izgubljen","lost gen"],e:"Izgubljena generacija (Lost Generation) termin je koji je Gertrude Stein primijenila na generaciju koja je dozivjela Prvi svjetski rat. Hemingway, Fitzgerald i Dos Passos kljucni su predstavnici."},
  {n:306,q:"Kasnije nazvan po azijskoj drzavi, ununtrij je bilo privremeno ime kojega radioaktivnog <strong>kemijskog elementa</strong> atomskog broja 113?",a:["nihonij","nihonium","nh","element 113"],p:["nihon","ununtr"],e:"Nihonium (Nh, element 113) sintetizirao je japanski tim u RIKEN istrazivackom centru 2004. Privremeno je nazvan ununtrij (113 latinskim prefiksima). IUPAC je 2016. potvrdio naziv Nihonium po Nihonu (Japan)."},
  {n:307,q:"Koje je <strong>nacionalnosti</strong> posljednji skakac s motkom koji je drzao svjetski rekord (nekoliko minuta u Rimu 1984.) prije gotovo tridesetogodisnje dominacije Sergeja Bubke?",a:["talijanska","talijian","italian"],p:["talijan","italian"],e:"Sergej Bubka (Ukraji/SSSR) dominirao je skokom s motkom od 1984. do 1994. Posljednji skakac koji je drzao rekord prije njega bio je talijanski atleticcar koji ga je drzao kratko 1984."},
  {n:308,q:"Koji je <strong>revolucionar</strong> i voda jakobinske diktature, fanatikacnom odanoscu Revoluciji stekao nadimak 'Nepotkupljivi', te je 1794. smaknut na giljotini?",a:["maximilien robespierre","robespierre"],p:["robespi"],e:"Maximilien Robespierre (1758-1794) bio je voda Revolucionarne vlade i kljucna figura Perioda terora. Njegova opsesija cnoctom dovela je do masovnih egzekucija, a naposljetku i do vlastite."},
  {n:309,q:"Suprotstavljajuci se poetici socijalistickog realizma i zauzimajuci se za slobodu pisanja, program kojeg je <strong>casopisa</strong> (1952.-1958.) po kojemu je nazvan narastaj mladih hrvatskih knjizevnika?",a:["krug","krug casopis"],p:["krug"],e:"Krug je bio casopis koji je od 1952. do 1958. objavljivao avangardnu hrvatsku knjizevnost. Narastaj autora koji su pisali za njega nazvan je 'krugovasima'. Casopis je bio vazna platforma za modernisticku knjizevnost."},
  {n:310,q:"Sa stihovima Tima Ricea i glazbom Eltona Johna, koji je nagraduivani <strong>mjuzikl</strong>, temeljen na slavnom animiranom filmu iz 1994., nakon Fantoma u operi i Chicaga najizvodeniji i po zaradi najznacajniji brodvejski mjuzikl u povijesti?",a:["kralj lavova","the lion king","lav kralj"],p:["kralj lav","lion king"],e:"Kralj lavova (The Lion King) brodvejski je mjuzikl koji je od 1997. jedan od najuspjesnijih u povijesti. Temeljen na istoimenom Disneyjevom animiranom filmu, do danas je zaradio vise od 1,7 milijardi dolara."},
  {n:311,q:"Nazvana prema sumarskom inzenjeru i strastvenom planinaru koji ju je projektirao, kako se zove 57 kilometara duga <strong>staza</strong> koja se proteze od Zavizana do Baskih Ostrtarija te prolazi kroz najljepse i najnepristupacnije dijelove Velebita?",a:["premuziceva staza","premuzic staza"],p:["premuz"],e:"Premuziceva staza je planinska staza duljine 57 km po Velebitu, sagradena 1930-ih. Projektirao ju je sumar Ante Premuzic. Jedna je od najtezih i najljepsih planinjarskih staza u Hrvatskoj."},
  {n:312,q:"Kako se zvao <strong>pas</strong> kojega je udomio sveucilisni profesor Hidesaburo Ueno, nakon cije ga je smrti jos punih devet godina pas cekao na istom mjestu, sve dok 1935. nije uginuo?",a:["hachiko","hachi"],p:["hachiko","hachi"],e:"Hachiko bio je akita pas iz Japana koji je svaki dan dolazio na tokijsku stanicu Shibuya cekajuci svog vlasnika profesora Uena, i nakon sto je ovaj umro 1925. nastavio dolaziti sve do vlastite smrti 1935."},
  {n:313,q:"Buduci da im je palube ubrzo prekrio pustinjski pijesak, kako je nazvana <strong>flota</strong> od 15 brodova koja je nakon Sestodnevnog rata ostala zarobljena u zatvorenom Sueskom kanalu?",a:["zuta flota","yellow fleet"],p:["zuta flota","yellow fleet"],e:"Zuta flota (Yellow Fleet) naziv je za 15 brodova koji su ostali zarobljeni u Sueskom kanalu od 1967. do 1975. zbog njegova zatvaranja poslije Sestodnevnog rata. Pijesak pustiinje prerio je palube, dajuci im zuto-smedi izgled."},
  {n:314,q:"Utemeljen 2008. u Zagrebu, kako se dvjema rijecima znakovito zove godisnji medunarodni <strong>festival fotografije</strong>, ciji program pokusava potaknuti promisljanje o globalno i drustveno vaznim politickim pitanjima?",a:["month of photography","mop","mesec fotografije"],p:["month of photo","mop"],e:"Festival ZagrebDox osnovan je 2005., a Festival fotografije u Zagrebu (Month of Photography Zagreb) organizira se od 2008. kao medunarodni festival koji promovira fotografiju kao medij drustvene komunikacije."},
  {n:315,q:"Uz to sto je poznata kao pjesma iz filma Diplomac, Mrs. Robinson Simona i Garfunkela u povijesti americkog sporta ostala je zapamcena po posveti kojoj bejzbolskoj <strong>ikoni</strong>?",a:["joe dimaggio","dimaggio"],p:["dimaggio","di maggio"],e:"Joe DiMaggio (1914-1999) bio je legendarni centar New York Yankeesa. Simon i Garfunkel su u Mrs. Robinson (1967.) pjevali 'Where have you gone, Joe DiMaggio?' evocirajuci americke heroje iz proslog doba."},
  {n:316,q:"Kako se zove kontroverzna <strong>mrezna stranica</strong> cije ime dolazi od dvaju popularnih zenskih imena u Sjevernoj Americi, osnovana 2002. s ciljem okupljanja ljudi koji su u braku ili vezama?",a:["ashley madison"],p:["ashley madison","ashley"],e:"Ashley Madison kontroverzna je stranica za izvanbracne afere osnovana 2002. pod sloganom 'Life is short. Have an affair'. 2015. je hakirana i objavljeni su podaci milijuna clanova."},
  {n:317,q:"Nekada se ova <strong>riba</strong> iz porodice Clupeidae koristila da skrene paznju psima tragacima u lovu na plijen, a po njoj se danas naziva fiktivna laz ili podatak koji se namjerno ubacuje kako bi odvukao pozornost?",a:["haringa","herring","red herring","crvena haringa"],p:["haringa","herring"],e:"Crvena haringa (red herring) logicka je zamka ili namjerna distrakcija. Termin potjece od prakse koriscenja dimljene haringe da se zavede trag mirisem pri treniranju pasa tragaca."},
  {n:318,q:"Kojoj je <strong>drzavi</strong> prvo olimpijsko zlato u povijesti 2016. donio Joseph Schooling pobijedivsi u Riju svog idola Michaela Phelpsa?",a:["singapur","singapore"],p:[],e:"Singapur je mali grad-drzava na jugu Malajskog poluotoka. Joseph Schooling 2016. je pobijedio Michaela Phelpsa na 100 m delfin stilom u Riju, donijevsi Singapuru prvo olimpijsko zlato u povijesti."},
  {n:319,q:"Kako se zove vrsta najcesce primjenjivane <strong>ljestvice</strong> za mjerenje stavova, sa sadrzanim tvrdnjama koje izrazavaju pozitivan ili negativan stav, u kojoj svaku tvrdnju prati najcesce pet mogucih odgovora kojima se izrazava stupanj slaganja?",a:["likertova ljestvica","likert ljestvica","likert"],p:["likert"],e:"Likertovu ljestvicu razvio je Rensis Likert 1932. Najcesce ima 5 stupnjeva slaganja, od potpunog neslaganja do potpunog slaganja. Najrasireniji je psihometrijski instrument u drustvenim istrazivanjima."},
  {n:320,q:"U koju se <strong>domenu zivog svijeta</strong>, s obzirom na gradu stanice, ubrajaju redovi Euryarchaeota, Crenarchaeota i Korarchaeota?",a:["arheje","prabakterije","archaea"],p:["arheje","prabakter","archae"],e:"Arheje (Archaea) su jednocelicni mikroorganizmi koji tvore jedan od triju domena zivota. Euryarchaeota i Crenarchaeota dvije su najvece grupe. Arheje su ceste u ekstremnim okruzenjima."},
  {n:321,q:"Kojemu se zapadnoafrickom <strong>bogu pauku</strong> pripisivala zasluga da je ljude naucio paliti vatru, a istodobno je bio i neopravljivsivi izvor smicalica?",a:["anansi","ananse"],p:["anansi"],e:"Anansi je lik iz mitologije naroda Akan u Gani, prikazan kao pauk koji simbolizira mudrost i prijevaru. Prenijet je putem africkiih robova u Karibe i Ameriku gdje je ostao ziv u pripovijedanju."},
  {n:322,q:"Kako se na P u antickoj retorici i poetici zove <strong>figura iskaza</strong> koja sadrzi igru rijecima slicnima na planu izraza, a razlicitima prema sadrzaju?",a:["paronomazija","paronomasia","igra rijeci"],p:["paronomaz"],e:"Paronomazija je retoricki postupak koji koristi rijeci slicnog zvuka ili pisanja ali razlicitog znacenja. Igra rijeci jedna je od najstarijih retorickih tehnika, prisutna od anticke knjizevnosti."},
  {n:323,q:"Oznacavana skraceno YNWA, koja je <strong>pjesma</strong> iz mjuzikla Karusel (1945.) Rodgersa i Hammersteina postala jedna od zastitnih navijackih pjesama nogometnih navijaca, osobito jednog kluba?",a:["youll never walk alone","you'll never walk alone","never walk alone"],p:["never walk alone","ynwa"],e:"You'll Never Walk Alone je pjesma iz mjuzikla Carousel (1945.) koju je 1963. snimila Gerry and the Pacemakers. Navijaci Liverpoola prihvatili su je kao klupsku himnu koja se pjeva na svakoj utakmici."},
  {n:324,q:"<strong>Koliko</strong> se igraca ukupno nalazi na terenu u utakmici kanadskog nogometa?",a:["24","dvadeset i cetiri"],p:["24"],e:"Kanadski nogomet igra se s 12 igraca po momcadi na terenu (za razliku od americkog s 11), sto ukupno daje 24 igraca na terenu. Igra se na terenu duljine 110 yardi."},
  {n:325,q:"Skup od 56 tornjeva sa zvonicima, koji su od 1999. na UNESCO-ovu popisu svjetske kulturne baštine, zajednicka je baština kojih <strong>dviju drzava</strong>?",a:["francuska i belgija","france and belgium","belgija i francuska"],p:["franc","belg"],e:"56 zvonara Belgije i Francuske uvrsteno je na UNESCO-ov Popis nematerijalne kulturne bastine 1999. Zvonare su bile simboli komunalne slobode u srednjovjekovnoj Flandriji."},
  {n:326,q:"Kako se zove 'najusamljenija' <strong>tocka</strong> na svijetu, zamišljeno mjesto udaljeno od najblizeg kopna oko 1450 nautickih milja, koje je 1992. definirao hrvatsko-kanadski istrazivac Hrvoje Lukatela, a ime dijeli s knjizevnim junakom ali i latinskom rijeci za odsutnost bilo koga?",a:["nemo","tocka nemo","point nemo"],p:["nemo"],e:"Tocka Nemo (Point Nemo) je 'pol nedostupnosti oceana', najudaljenija tocka od svakog kopna. Definirao ju je Hrvoje Lukatela 1992. Naziva se po Kapetanu Nemu (lat. nemo = nitko)."},
  {n:327,q:"Premda je dugo vladalo misljenje da je rasirenih nogu pozirala Joanna Hiffernan, ipak je ustanovljeno da je balerina pariske Opere Constance Quéniaux bila model za koju cuvenu <strong>sliku</strong> Gustavea Courbeta?",a:["podrijetlo svijeta","lorigine du monde","l origine du monde"],p:["podrijetlo","origine"],e:"L'Origine du monde (Podrijetlo svijeta, 1866.) Gustavea Courbeta je realisticna slika zenskog tijela, jedna od najkontroverznijih u povijesti. Bila je u vlasnistu Jacquesa Lacana, danas je u Musée d'Orsay."},
  {n:328,q:"Poznat i kao tenore robusto, koji se <strong>pridjev</strong> koristi za tip dramskog tenora koji je, u zahtjevu za snagom tona i izdrzljivoscu, stvorio Richard Wagner?",a:["herojski tenor","heldentenor","herojski"],p:["herojsk","helden"],e:"Heldentenor (herojski tenor) je tip opernog glasa za Wagnerove heroje. Zahtijeva iznimnu snagu i izdrzljivost za dugotrajne dramaticne uloge poput Tristana, Siegfrieda i Radamesa."},
  {n:329,q:"Kako se zove nagraduivani 13-minutni <strong>animirani film</strong> Zdenka Gasparovica, nadahnut glazbenim minijaturama za glasovir Erica Satieja?",a:["satiemanija","satie mania"],p:["satiemanij","satie man"],e:"Satiemanija (1978.) nagraduivani je animirani film Zdenka Gasparovica nastao po glazbi Erica Satieja u izvedbi Alda Ciccolinija. Remek-djelo je Zagrebacke skole crtanog filma."},
  {n:330,q:"Kako se zovu <strong>vještice</strong> koje se, prema legendi, na Valpurginu noc sastaju na Kleku iznad Ogulina, a zbog zloga sporazuma s vragom mogu donijeti bolesti, vremenske nepogode ili cak kravama oduzimati mlijeko?",a:["coprnice","vještice s Kleka","klek vještice"],p:["coprn","klek"],e:"Coprnice su u hrvatskoj folkloru vještice koje se na Valpurginu noc (30. travnja) sastaju na Kleku kraj Ogulina. Prema legendi, sklopile su pakt s davlom i cine zlo."},
  {n:331,q:"Koja se <strong>rijeka</strong>, cije ime na vecini istocnih indoeuropskih jezika znaci 'rijeka' ili jednostavno 'voda', ulijeva u istoimeni zaljev cineci ga najduljim estuarijem na svijetu?",a:["ob","rijeka ob"],p:["ob"],e:"Rijeka Ob jedna je od najvecih rijeka Sibira, duga oko 3650 km. Njezin estuarij (Obski zaljev) najdulje je estuarno podrucje na svijetu. Ime 'ob' na raznim jezicima znaci jednostavno 'voda' ili 'rijeka'."},
  {n:332,q:"S prikazom viteske borbe u logu, kako se zove jedna od najstarijih i najvecih <strong>tvrtki</strong> olovaka, uredskog i umjetnickog pribora, osnovana u njemackom Steinu 1761.?",a:["faber-castell","faber castell"],p:["faber"],e:"Faber-Castell je njemacki proizvodac pisaceg pribora osnovan 1761. Naziv je nastao spajanjem obiteljskih prezimena osnivacke obitelji Faber i grafa von Castella koji se 1898. ozenio nasljednicom tvrtke."},
  {n:333,q:"Poznate i kao Las Leonas, reprezentativke Argentine u kojemu su <strong>sportu</strong>, osvojivsi srebro u Sydneyju (poraz od Australije 3-1), postale prva zenska ekipa iz te zemlje s osvojenom olimpijskom medaljom u nekom timskom sportu?",a:["hokej na travi","field hockey"],p:["hokej na travi","field hockey"],e:"Argentinska zenska hokejaska reprezentacija Las Leonas srebro je osvojila na Olimpijskim igrama u Sydneyju 2000. Bile su prva zenska argentinska ekipa s olimpijskom medaljom u timskom sportu."},
  {n:334,q:"Iako je tu <strong>praksu</strong> Benjamin Franklin spominjao u pismu urednicima, ideju su neovisno jedan od drugog prvi sluzbeno predlozili novozelandski entomolog George Hudson i britanski poduzetnik William Willett?",a:["ljetno racunanje vremena","daylight saving time","ljetno racunanje","pomak sata"],p:["ljetno racunan","daylight saving"],e:"Ljetno racunanje vremena (DST) je praksa pomicanja sata za jedan sat naprijed u proljecut kako bi se iskristilo vise dnevnog svjetla. Njemacka ga je prva uvela 1916. za stednju energije u ratno doba."},
  {n:335,q:"Kako se zove specifican <strong>tip bankarstva</strong> u kojemu nema placanja i primanja kamate, a banke posluju na bazi podjele profita ili s pomocu drugih dopustenih oblika?",a:["islamsko bankarstvo","sharia banking","islamske financije"],p:["islamsk","sharia"],e:"Islamsko bankarstvo temelji se na serijatskim nachelima koja zabranjuju riba (kamate). Umjesto toga banke koriste profit-sharing modele poput mudaraba i musharaka."},
  {n:336,q:"Ova kartaška <strong>igra</strong> sa špilom od 32 karte cesto se naziva 'najfrancuskijom' od svih igara, a cilj je svakog igraca zamjenom stvoriti sto jacu kombinaciju u sest dijeljenja. Kako se zove ta igra ako naziv dijeli s prezimenom trostrukog svjetskog prvaka Formule 1 osamdesetih?",a:["piquet","pike"],p:["piquet","pike"],e:"Piquet je dvoclovjecna kartaška igra s 32 karte koja potjece iz Francuske iz 16. st. Ime dijeli s Nelsonom Piquetom, brazilskim trkachem koji je tri puta osvoji naslov prvaka F1."},
  {n:337,q:"Koja je tradicionalna <strong>djelatnost</strong> karakteristicna za otok Krapanj, umijece kojim je mještane pocetkom 18. st. poucio fra Antun Grk s Krete?",a:["spuzvarstvo","branje spuzvi","spuzva"],p:["spuzv"],e:"Spuzvarstvo je tradicijsko branje morskih spuzvi koje je specifino za otok Krapanj pokraj Sibenika. Fra Antun je stanovnike naucio ronjenju za spuzve pocetkom 18. st., a tradicija se odrz do danas."},
  {n:338,q:"Koja se <strong>zivotinja</strong> iz porodice supljoroza do 2015. kao simbol nalazila na logu ciparske zrakoplovne kompanije Cyprus Airways i od 2008. krasi nalicja ciparskog izdanja kovanica od 1, 2 i 5 eurocenta?",a:["muflon"],p:["muflon"],e:"Muflon (Ovis gmelini) je europska divlja ovca, najmanji divlji ovnoroci. Na Cipru i Sardiniji postoje izolirana autohtona jata. Na Cipru je simbol nacionalne bastine."},
  {n:339,q:"Kako se zove <strong>grana</strong> hidrologije koja se bavi istrazivanjem i proucavanjem jezera?",a:["limnologija","limnology"],p:["limnolog"],e:"Limnologija je znanstvena disciplina koja proucava kopnene vodene ekosustave — jezera, ribnjake, mocvare i potoke. Termin potjece od grcke rijeci limne (jezero)."},
  {n:340,q:"Kako se u drevnom Izraelu zvala <strong>skupstina</strong> ili vijece mudraca koje se sastojalo od 23 suca u svakom zidovskom gradu, dok je isti pojam uz pridjev 'veliki' oznacavao vrhovni sud od 71 clana?",a:["sanhedrin","sanhedrin"],p:["sanhedrin"],e:"Sanhedrin je bio vrhovni sudski i zakonodavni organ drevnog Izraela. Veliki Sanhedrin od 71 clana bio je vrhunski autoritet za vjerska i pravna pitanja. Raspusten je 425. n. e."},
  {n:341,q:"Simbol St. Louisa, 192 metara visok luk Gateway, djelo je kojega finsko-americkog <strong>arhitekta</strong>, poznatog po neofuturistickom stilu?",a:["eero saarinen","saarinen"],p:["saarinen"],e:"Eero Saarinen (1910-1961) bio je finsko-americki arhitekt poznat po inovativnim formama. Gateway Arch u St. Louisu (1963.) je najpoznatije djelo. Projektirao je i TWA terminal u New Yorku."},
  {n:342,q:"Nastalo iz dviju skica Grcka glazbena drama i Sokrat i tragedija, kako se zove prvo objavljeno <strong>djelo</strong> Friedricha Nietzschea iz 1872.?",a:["rodenje tragedije","die geburt der tragodie","rodjenje tragedije iz duha glazbe"],p:["rodenje traged","geburt der trag"],e:"Rodenje tragedije iz duha glazbe (1872.) je Nietzscheovo prvo objavljeno djelo. U njemu analizira napetost izmedju apolonskog (razum, forma) i dionizijskog (strast, kaos) principa u grckoj tragediji."},
  {n:343,q:"Koji je <strong>mongolski vladar</strong> 1271. osnovao kinesku dinastiju Yuan, cijom je vladavinom Kinom vladala strana dinastija?",a:["kublaj kan","kublai khan","kublaj-kan"],p:["kublaj","kublai"],e:"Kublaj-kan (1215-1294) bio je unuk Dzingis-kana i osnivac kineske dinastije Yuan. Za njegove vladavine Kina je bila najvece carstvo u povijesti. Posjetio ga je Marco Polo."},
  {n:344,q:"Kojega je <strong>pjesnika</strong> car August 8. godine protjerao na obale Crnoga mora, gdje je u progonstvu napisao zbirke elegija Zalibnice i Poslanice s Crnoga mora?",a:["ovidije","publius ovidius naso","publije ovidije nazon"],p:["ovidij","ovidius"],e:"Publije Ovidije Nazon (43. pr. Kr. - 17. n. e.) jedan je od najvecih rimskih pjesnika. August ga je prognan vjerojatno zbog eroticke poezije (Ars amatoria) i osobne uvrede. Razlog je ostao tajna."},
  {n:345,q:"Koju su <strong>psihoaktivnu tvar</strong> formule C21H30O2 1964. prvi izolirali i objasnili njezinu strukturu izraelski kemicari Raphael Mechoulam i Yehiel Gaoni?",a:["tetrahidrokanabinol","thc","kanabinol"],p:["tetrahidrokan","thc"],e:"Tetrahidrokanabinol (THC) je glavna psihoaktivna supstanca konoplje (Cannabis sativa). Mechoulam i Gaoni izolirali su ga 1964. u Izraelu. THC se koristi u medicinskim tretmanima boli i muicnine."},
  {n:346,q:"Nezavisni danski proizvodac videoigara Playdead pojavio se 2010. kojom megapopularnom puzzle-platform <strong>videoigrom</strong> crno-bijelih tonova, nazvavsi je prema latinskom izrazu za 'rub' ili 'granicu'?",a:["limbo"],p:["limbo"],e:"Limbo (2010.) je puzzle-platformer koji je razvio danski studio Playdead. Igra u crno-bijeloj estetici o djecaku koji trazi sestru u surealnom svijetu. Naziv dolazi od latinskog limbus (rub)."},
  {n:347,q:"Kojim se <strong>slovom</strong> grckog alfabeta oznacava efekt u kojemu prostor utjece na ljudsku percepciju vremena stvarajuci vremensku iluziju?",a:["kapa","kappa"],p:["kapa","kappa"],e:"Kappa efekt je psihologijska iluzija u kojoj prostorna udaljenost utjece na percepciju protoka vremena. Shiri vremenski razmak percipira se kao dulji ako su udaljeniji objekti."},
  {n:348,q:"Koja je <strong>korporacija</strong> za svoju marketinsku kampanju 1995. platila oko tri milijuna dolara grupi Rolling Stones zbog koristenja pjesme Start Me Up?",a:["microsoft"],p:["microsoft"],e:"Microsoft je 1995. platio Rolling Stonesima oko 3 milijuna dolara za koristenje pjesme Start Me Up u reklami za Windows 95. Bila je to jedna od najskupljih korporativnih muzickih dozvola tada."},
  {n:349,q:"Na kojim je Zimskim <strong>olimpijskim igrama</strong> plesni par Marina Anissina i Gwendal Peizerat Francuskoj donijo prvo zlato u umjetnickom klizanju nakon 1932.?",a:["salt lake city 2002","2002 zimske olimpijske igre","salt lake city"],p:["salt lake","2002"],e:"Zimske olimpijske igre 2002. odrzane su u Salt Lake Cityju, Utah, SAD. Marina Anissina i Gwendal Peizerat osvojili su zlato u plesnom klizanju za Francusku."},
  {n:350,q:"Deltiologija je pojam koji se odnosi na proucavanje i skupljanje — <strong>cega</strong>?",a:["razglednica","razglednice","postcards"],p:["razglednic","postcard"],e:"Deltiologija je hobi skupljanja i proucavanja razglednica. Termin je skovao profesor Randall Rhoades 1945. Razglednice su se pojavile u drugoj polovici 19. st."},
  {n:351,q:"Imenovan po ruskom arhipelagu u arktickom krugu, kako se naziva polarni <strong>opticiki fenomen</strong> koji nastaje zbog prelamanja Sunceve svjetlosti izmedju atmosferskih tankih slojeva zraka?",a:["efekt novaje zemlje","novaja zemlja"],p:["novaja zemlja"],e:"Efekt Novaje Zemlje je arkticka atmosferska optucka pojava zbog koje Sunce izgleda da je izaslo iznad horizonta kada je zapravo jos ispod. Opazio ga je prvi put clano Barentsove ekspedicije."},
  {n:352,q:"Uplaseni su roditelji u suradnji s Katolickom crkvom u razdoblju 1960-1962. s Kube u SAD prebacili vise od 14 tisuca djece u <strong>operaciji</strong> poznatoj pod kojim knjizevnim imenom?",a:["petar pan","peter pan","operacija petar pan"],p:["petar pan","peter pan"],e:"Operacija Petar Pan (Pedro Pan) bila je tajna humanitarna akcija 1960-1962. u kojoj je 14.048 djece iz Kube poslano u SAD bez roditelja, u strahu od komunisticke indoktrinacije."},
  {n:353,q:"Koji je <strong>skladatelj</strong> autor opseznog zborskog djela Njemacki rekvijem op. 45 iz 1868., kompozicije nadahnute tugom za netom umrlom majkom?",a:["johannes brahms","brahms"],p:["brahms"],e:"Johannes Brahms (1833-1897) njemacki je romananticni skladatelj. Njemacki rekvijem (Ein deutsches Requiem, 1865-1868.) nije liturgijsko djelo vec meditacija o gubitku i smirenju, nadahnuta smrcu njegove majke."},
  {n:354,q:"Nastao iz pera Ivane Brlic-Mazuranic 1937., naslovni junak Jasa Dalmatin potkralj je koje <strong>savezne drzave</strong> na zapadu Indije?",a:["gujurat","gujarat"],p:["gujurat","gujarat"],e:"Jasa Dalmatin, potkralj od Gujurata (1937.) roman je Ivane Brlic-Mazuranic o dalmatinskom avanturistu. Gujarata (Gujurat) je indijska savezna drzava na zapadu Indije poznata po kulturi i industrijskom razvoju."},
  {n:355,q:"Pod imenom Max Stierlitz krije se sovjetski obavjestajac Maksim Isajev iz ciklusa spijunskih romana Julijana Semjonova, a popularnost dobio ekranizacijom u TV <strong>seriji</strong> iz 1973.?",a:["sedamnaest trenutaka proljeca","seventeen moments of spring"],p:["sedamnaest trenutaka","seventeen moments"],e:"Sedamnaest trenutaka proljeca (1973.) je kultna sovjetska TV serija o spijunu Maksimim Isajevu (Max Stierlitz) koji djeluje duboko u nacistickom Njemackom. Vjaceslav Tihonov utjelovio je lika."},
  {n:356,q:"Na groblju ototica San Michele u blizini kojega je <strong>grada</strong> pocivaliste glazbenih velikana Igora Stravinskog i Sergeja Djagileva, redatelja Ezre Pounda i pisca Josifa Brodskog?",a:["venecija","venice"],p:["venecij","venice"],e:"Groblje San Michele je groblje na otocu izmedju Venecije i Murana. Mnoge poznate osobe kao Igor Stravinski, Ezra Pound i Sergej Djagilev tamo su pokopani."},
  {n:357,q:"Prema francuskom za 'skitnicu' ili 'lutalicu', kako se zove <strong>osoba</strong> koja se slobodno seta bez posebno zacrtana cilja, a proslavio ju je Walter Benjamin u pariskim esejima?",a:["flaner","flaneur"],p:["flaner","flaneur"],e:"Flaneur (franc. skitinica) je koncepta gradskog setaca bez cilja koji uiva u gradskom zivotu kao promatrac. Walter Benjamin ga je popularizirao u svojim esejima o Parizu i Charlesu Baudelaireu."},
  {n:358,q:"Smjesten u podnozu planine Meru, grad Arusha bio je od 1994. do 2015. sjediste Medunarodnog suda za ratne zlocine pocinjene u Ruandi. Na sjeveroistoku koje se <strong>drzave</strong> nalazi Arusha?",a:["tanzanija","tanzania"],p:["tanzanij","tanzania"],e:"Tanzanija je istocnoafricka drzava nastala ujedinjenjem Tanganyike i Zanzibara 1964. Arusha je turisticko srediste s cuvenim safari podrucjima."},
  {n:359,q:"Smjesten na jugozapadu Svicarske, kako se zove svicarski <strong>kanton</strong> s glavnim gradom Sionom, nakon Graubündena i Berna povrsinoni najveci?",a:["valais","wallis"],p:["valais","wallis"],e:"Valais (njem. Wallis) je kanton na jugozapadu Svicarske, poznat po vinogradima, skijaliscima i alpskim planinama. Glavni grad je Sion. Dom je Matterhorna i poznatih skijalista Zermatata."},
  {n:360,q:"Protiv kojega je turskog nogometnog <strong>kluba</strong> Hajduk zaigrao u prvom nastupu na novom Poljudskom stadionu, u rujnu 1979. u utakmici 1. kola Kupa prvaka?",a:["trabzonspor"],p:["trabz"],e:"Trabzonspor je turski nogometni klub iz grada Trabzona. Hajduk je na otvaranju Poljudskog stadiona u rujnu 1979. igrao protiv Trabzonpora u Europskom kupu prvaka."},
  {n:361,q:"Kako se zove <strong>podrucje geometrije</strong> koje se bavi proucavanjem geometrijskih likova u ravnini i njihovim odnosima?",a:["planimetrija","planimetry"],p:["planimetri"],e:"Planimetrija je grana geometrije koja se bavi proucavanjem ravninskih (2D) geometrijskih likova poput trokuta, cetverokuta i kruznica. Za razliku od stereometrije koja proucava 3D likove."},
  {n:362,q:"Kako se zvala <strong>jedrilica</strong> Mladena Suteja, kojom je 1994. pocevsi plovidbu obisao svijet meridionalnim rutama?",a:["hrvatska cigra","hrvatska cigra jedrilica"],p:["cigra"],e:"Hrvatska cigra jedrilica je na kojoj je Mladen Sutej 1994-1997. obisao svijet meridionalnim rutama, prolazeci kroz Arktik i Antarktiku."},
  {n:363,q:"Kako se, prema kineskom za 'crni zmaj', zove napola fermentiran <strong>caj</strong> obradjen iz lisca Camellia sinensis koji sadrzi vise teina nego zeleni caj?",a:["oolong","wu long","wulong"],p:["oolong","wu long"],e:"Oolong (wulong) je djelomicno oksidirani caj koji se uzgaja uglavnom u Kini i na Tajvanu. Ima karakteristiku izmedju zelenog i crnog caja, a poznate su mu prednosti za zdravlje i metabolizam."},
  {n:364,q:"Planinski lanac nazvan je po ocu, a njegov najvisi vrh (4509 metara), ujedno i najvisa tocka Papue Nove Gvineje, po mlajdem sinu. Sin je Wilhelm, a otac je koji <strong>drzavnik</strong>?",a:["otto von bismarck","bismarck"],p:["bismarck"],e:"Bismarckovo gorje u Papui Novoj Gvineji nazvano je po Ottu von Bismarcku (1815-1898), njemackim kancelarem koji je ujedninio Njemacku. Vrh Wilhelm (4509 m) nazvan je po sinu."},
  {n:365,q:"Osvojivsi Oscare za filmove Gravitacija, Birdman i Povratnik, Emmanuel Lubezki jedina je osoba u povijesti s tri uzastopna Oscara u kojoj <strong>kategoriji</strong>?",a:["najboja fotografija","best cinematography","kamera","snimanje"],p:["fotografij","cinemat","kamera"],e:"Emmanuel Lubezki meksicki je snimatelj koji je osvoji tri uzastopna Oscara za Najboju fotografiju: Gravitacija (2014), Birdman (2015) i Povratnik (2016). Jedini je snimatelj s takvim dostignacem."},
  {n:366,q:"Kako se zove <strong>tip novinarstva</strong>, ciji je tvorac novinar Hunter S. Thompson, karakteriziran veoma subjektivnom formom izvjestavanja s upotrebom sarkazma i pretjerivanja?",a:["gonzo novinarstvo","gonzo journalism","gonzo"],p:["gonzo"],e:"Gonzo novinarstvo je stil koji je razvio Hunter S. Thompson 1970-ih. Novinar postaje dio price i pise u prvom licu, s intenzivnom upotrebom sarkazma, psovki i subjektivnih opservacija."},
  {n:367,q:"Koji je kultni <strong>indie rock-bend</strong> osnovan 1984. u New Jerseyju, a ime mu je sa spanjolskog doslovno prevedeno 'imam je'?",a:["yo la tengo"],p:["yo la tengo"],e:"Yo La Tengo je americki indie rock bend osnovan 1984. u Hobokenu, New Jersey. Ime potjece od spanjolskog izraza 'yo la tengo' (ja je imam), koji se koristio medu igraccima bejzbola."},
  {n:368,q:"Pokazavsi se jedinim na setu koji zna koristiti aparat za kavu, James Michael Tyler dobio je ulogu kojega 'bjelokosog' <strong>lika</strong> iz popularne americke TV serije Prijatelji?",a:["gunther"],p:["gunther"],e:"Gunther je lik iz americke komedije Prijatelji (Friends, 1994-2004.) kojega je glumio James Michael Tyler. Lik se pojavljuje kao ljubomoran prijatelj koji tajno voli Rachel."},
  {n:369,q:"Poznat samo i kao pop, kako se zove hrvatski glagoljaski <strong>pisar</strong>, kaligraf i iluminator iz 15. st., ciji je najpoznatiji zapis onaj iz 1493. u kojemu opisuje stanje u Hrvatskoj?",a:["pop martinac","martinac"],p:["martinac"],e:"Pop Martinac bio je glagoljaski pisar iz 15. st. ciji je autograf iz 1493. Zapisi o pustoseniju Krbavske bitke jedan je od najvaznijih izvornih tekstova za hrvatsku povijest."},
  {n:370,q:"Cije je zivotno djelo fantasticno-satiricni roman u pet knjiga Gargantua i Pantagruel, genijalna satira zastarjelih srednjovjekovnih pogleda koji je postalo ogledalom renesansnog covjeka?",a:["francois rabelais","rabelais"],p:["rabelais"],e:"François Rabelais (oko 1494-1553) bio je francuski renesansni pisac, humanist i lijecnik. Gargantua i Pantagruel (1532-1564.) satiricni je roman o dva diva koji kritizira scholastiku i slavi humanisticke vrijednosti."},
  {n:371,q:"Uz svanski, lazijski i mingrelski, koji je s oko cetiri milijuna govornika najrasprostreniji <strong>jezik</strong> izolrane porodice jezika koju zajedno tvore?",a:["gruzijski","georgian"],p:["gruzij","georgian"],e:"Gruzijski je sluzbeni jezik Gruzije i najrasprostranjeniji od kartvelskih (juznokauvkaskih) jezika. Ima jedinstveno pismo (Mkhedruli) koje se koristi iskljucivo za gruzijski."},
  {n:372,q:"Nazvana po sredisnjoj kanadskoj provinciji, odakle tradicionalno dolazi proizvodnja posebne vrste psenice otporne na hladnocu, kako se zove vrsta bogatog <strong>brasna</strong> s visokim postotkom glutena?",a:["manitoba brasno","manitoba flour"],p:["manitoba"],e:"Manitoba brasno jest vrsta tvrdog psenicnog brasna s visokim udjelom glutena (14%+). Odlicno je za kruhovni kruh, pizzu i pecivo koje treba dugo fermentirati."},
  {n:373,q:"Ako se u dzudu protivnika baci na leda s razumnom kolicinom snage, automatski se pobjedjuje zbog maksimalno dobivenog broja bodova koji se zove — <strong>kako</strong>?",a:["ippon"],p:["ippon"],e:"Ippon je najvisi rezultat u dzudu kojim se automastki pobjedjuje. Oznacava savrsenu izvedbu bacanja, zadrzavanja ili predaje. Naziv dolazi od japanskog 'ichi-hon' — jedan bod."},
  {n:374,q:"Dok binarni sustav ima bazu 2, dekadski 10, heksadekadski 16, koji je <strong>broj</strong> u bazi vigezimalnog brojevnog sustava?",a:["dvadeset","20"],p:["dvadeset","20"],e:"Vigezimalni brojevni sustav (vigesimal) koristi bazu 20. Koristili su ga Maya, Kelti i neka australska autohotona plemena. Maya su razvili najsofisticiraniji vigezimalni matematicki sustav."},
  {n:375,q:"Zbog blagotvornih etericnih ulja koja pogoduju kozi, snop svjezih grantica kojega se <strong>listopadnog stabla</strong> iz porodice Betulaceae koristi u originalnoj finskoj sauni za lupkanje?",a:["breza","birch","betula"],p:["breza","birch"],e:"Breza (Betula) je listopadno drvo koje je simbol finskog nacionalnog identiteta. Brezove vjencanice (vihta) koristene u sauni daju mirisna eterana ulja i poboljsavaju cirkulaciju."},
  {n:376,q:"U Hrvatskoj akademiji znanosti i umjetnosti u Zagrebu cuva se osamnaestostoljetna violina Guarneri King na kojoj je svirao koji slavni hrvatski <strong>violinist</strong> od 1924. nastanjen u SAD-u?",a:["zlatko balokovic","balokovic"],p:["balokovic"],e:"Zlatko Baloković (1895-1965) bio je jedan od najslavnijih violinista prve polovice 20. st. Nastanio se u SAD-u 1924. i bio jedan od prvih jugoslavenskih glazbenika koji je postigao medjunarodnu slavu."},
  {n:377,q:"Dolazeci od grckih rijeci za 'isto' i 'glava', kako se zove <strong>nacin komponiranja</strong> ljudskih likova u umjetnickim djelima kada su sve glave prikazane u istoj visini?",a:["izokefalija","isocephaly"],p:["izokefalij","isocephal"],e:"Izokefalija je kompozicijsko nacel koje su koristili anticko-egipatski, grecki i rimski umjetnici, posebno u reljefima i freskama. Sve glave su na istoj visini bez obzira na poziciju tijela."},
  {n:378,q:"Nazvane prema austrijskom istrazivcu Aloisu koji ih je otkrio 1808., kako se zovu karakteristicne <strong>strukture</strong> nadjene u metalnim meteoritima, koje su osnova za razlikovanje zemaljskog od izvanzemaljskog zeljeza?",a:["widmanstattenove linije","widmanstatten"],p:["widmanst"],e:"Widmanstattenove linije (figure) kristalna su struktura koja se pojavljuje u niklenom zeljezu meteorita. Nastaju ekstremno sporim hladenjem taljene mase tisucama godina."},
  {n:379,q:"Tvrtka Hasselblad, koja proizvodi kamere i fotografsku opremu, poznata po kamerama koriscenima za snimanje Mjeseca u misijama Apollo, osnovana je 1841. u kojoj danasnjoj <strong>drzavi</strong>?",a:["svedska","sweden"],p:["svedsk","sweden"],e:"Hasselblad je svedska tvrtka za profesionalnu fotografsku opremu, osnovana 1841. u Göteborgu. Hasselblad kamere koristili su astronauti misija Apollo na Mjesecu 1969-1972."},
  {n:380,q:"U slucaju prekida utakmice zbog vremenskih ili drugih okolnosti, u kojemu se <strong>sportu</strong> koristi matematicka metoda izracuna Duckworth-Lewis-Stern za kalkulaciju broja bodova?",a:["kriket","cricket"],p:["kriket","cricket"],e:"Kriket je sport koji koristi Duckworth-Lewis-Stern (DLS) metodu od 1997. kada se utakmica ne moze dovrsiti zbog kise ili loseg vremena. Metoda odreduje revidirani cilj za skupinu u drugoj izmjeni."},
  {n:381,q:"Kako se jednom rijecju zove sustavna <strong>primjena ekonometrijskih i statistickih metoda</strong> u istrazivanju gospodarske i socijalne povijesti?",a:["kliometrija","kliometrika","cliometrics"],p:["kliometri","cliometri"],e:"Kliometrija je disciplina koja primjenjuje ekonometriju, statistiku i ekonomsku teoriju u analizi povijesnih podataka. Termin dolazi od Klio, muze povijesti."},
  {n:382,q:"Koja se <strong>tehnika</strong> sastoji od lijepljenja isjeckanh i aranzziranih papira na neku obojenu povrsinu, a u prijevodu s francuskog znaci 'isijeci' ili 'sjeckati'?",a:["dekupaz","decoupage"],p:["dekupaz","decoupage"],e:"Dekupaz (decoupage) je tehnika ukrašavanja objekata ljepenjem isjecaka papira, tkanina ili folija. Potjece iz 17. st. u Kini i Japanu, a u Europi je popularizirana u Veneciji 18. st."},
  {n:383,q:"Kako se zove <strong>zaljev</strong> izmedju Jemena na juznoj obali Arapskog poluotoka i Somalije na Rogu Afrike, vazna poveznice Sredozemnnog i Arapskog mora?",a:["adenski zaljev","gulf of aden","aden"],p:["adenski","aden"],e:"Adenski zaljev spaja Crveno more s Indijskim oceanom. Strateski je kljucan za brodarstvo i naftnu tranzit. U posljednjem desetljecu poznat je po piratskim napadima."},
  {n:384,q:"Koji je bizantski <strong>car</strong> sredinom 10. st. napisao djelo O upravljanju carstvom, jedan od najznacajnijih izvora za proucavanje rane hrvatske povijesti?",a:["konstantin vii porfirogenet","konstantin vii","konstantin porfirogenet"],p:["konstantin","porfirogenet"],e:"Konstantin VII. Porfirogenet (905-959.) bio je bizantski car-pisac koji je napisao vise kljucnih povijesnih i administrativnih tekstova. De administrando imperio nezamjenjiv je izvor za povijest Balkana."},
  {n:385,q:"Umm Kulthum smatra se jednom od najznacajnijih pjevacica arapskog svijeta. U kojoj je <strong>drzavi</strong>, cija joj je vlada posvetila muzej u glavnom gradu, rodena i zivjela?",a:["egipat","egypt"],p:["egipat","egypt"],e:"Umm Kulthum (1904-1975) bila je egipatska pjevacica smatrana 'Zvijezdom Istoka'. Njena kocerca su pratili milijuni u cijelom Arabskom svijetu. Egipatska vlada posvetila joj je muzej u Kairu."},
  {n:386,q:"Na Tajlandu nang, u Indoneziji wajang, u Turskoj karagöz i hacivat, u Indiji tholu bommalata — primjeri su koje <strong>vrste kazalista</strong>?",a:["kazaliste sjena","shadow theatre","lutkarsko kazaliste"],p:["kazaliste sjena","shadow theatre","sjenk"],e:"Kazaliste sjena je kazalisna forma u kojoj se sjene lutaka ili figura projiciraju na osvijetljeni zaslon. Ima dugu tradiciju u Aziji i Bliskom istoku."},
  {n:387,q:"Koji je komicni redatelj, scenarist i glavni glumac komedije Vrijeme igre (Playtime) iz 1967., satire potrosackog drustva realizirane tehnikom sirokoga platna, cesto proglasavane jednim od najbosljih filmova svih vremena?",a:["jacques tati","tati"],p:["tati"],e:"Jacques Tati (1907-1982) bio je francuski redatelj i komicni glumac. Playtime (1967.) je satira modernog urbanog zivota, snimana na specijalnoj mega-edicijoj scenu velicine grada."},
  {n:388,q:"Koja je bejzbolska <strong>momcad</strong>, originalno iz njujorskog Brooklyna, a preseljena u Los Angeles 1957., ime dobila po gradskim pješacima poznatima po sposobnosti brzog sklanjanja s puta jurecim tramvajima?",a:["dodgers","los angeles dodgers","brooklyn dodgers"],p:["dodgers"],e:"Los Angeles Dodgers jedna je od najuspjesnjih bejzbolskih momcadi. Originalno iz Brooklyna (Brooklyn Trolley Dodgers), preselili su se u LA 1957. Ime su dobili po navici izbjegavanja tramvaja."},
  {n:389,q:"Koji se <strong>termin</strong> u marksizmu koristi kako bi se opisali deklasisrani slojevi drustva koji zive na marginama, kao sto su skitnice, beskucnici, prosjaci i sitni kriminalci?",a:["lumpenproletarijat","lumpen"],p:["lumpen"],e:"Lumpenproletarijat (njem. krpeni proletarijat) je Marxov termin za dno drustvene ljestvice — ljude bez stalnog zaposlenja i klasne svijesti. Marx ih je smatrao potencijalnom kontrarevolucionarnom snagom."},
  {n:390,q:"Kako se zove <strong>umak</strong>, popularna delikatesa u vrijeme Rimskog Carstva, koji se dobiva tako da se riba ostavi da fermentira u soli ili slanoj vodi nekoliko tjedana ili mieseci?",a:["garum"],p:["garum"],e:"Garum je fermentirana riblja omaka bila kljucni sastojak rimske kuhinje, slicna azijskim ribjim umacima. Koristio se kao univerzalni aromaticni umak i bio izuzetno cijenjen i skup."},
  {n:391,q:"Koja je <strong>pjesma</strong> grupe The Police s albuma Synchronicity inspirirana knjigom Paula Bowlesa Zaklon od neba (The Sheltering Sky)?",a:["tea in the sahara"],p:["tea in the sahara"],e:"Tea in the Sahara je pjesma s albuma Synchronicity (1983.) grupe The Police, inspirirana romanom Paula Bowlesa. Bernardo Bertolucci snimio je 1990. film prema toj knjizi."},
  {n:392,q:"Povezan s pomorskom tradicijom iz doba velikih geografskih otkrica, koji se navigacijski <strong>instrument</strong> nalazi na zastavi Portugala?",a:["obrucasta sfera","armilarna sfera"],p:["obrucasta","armilarn"],e:"Armilarna sfera (armillary sphere) navigacijski je instrument koji prikazuje kretanje nebeskih tijela. Na zastavi Portugala simbol je pomorske tradicije i zlatnog doba Velikih otkrica."},
  {n:393,q:"Nazvani tako sto su, nasuprot tadashnjoj plemickoj modi kratkih hlaca, ispod kojena nosili hlace duljih nogavica, kako su se zvali <strong>pripadnici</strong> Nacionalne garde iz 1793. koji su postali sinonim za ultrarevolucionare?",a:["sankiloti","sans-culottes"],p:["sankilot","sans-cul"],e:"Sans-culottes (franc. bez kratkih hlaca) bili su radnicka klasa i siromasi koji su bili okosnica Revolucije. Naziv su dobili jer su nosili duge hlace (pantalone) za razliku od aristokracije koja je nosila culottes."},
  {n:394,q:"Koji je njemacko-americki razvojni <strong>psiholog</strong> i psihoanaliccar, dobitnik Pulitzerove nagrade 1970. za djelo Ghandijeva istina, skovao pojam 'kriza identiteta'?",a:["erik erikson","erikson","erik homburger erikson"],p:["erikson"],e:"Erik Erikson (1902-1994) bio je njemacko-americki psiholog koji je razvio teoriju psihosocijalnog razvoja u 8 faza. Termin 'kriza identiteta' skovao je na temelju svojih iskustava."},
  {n:395,q:"Nazvan po jednom od najvecih igraca u povijesti, americkom 'Mr. Pocket Billiards' Williamu Josephu, kako se zove godisnj <strong>turnir</strong> u devetki (nine-ball pool), popularnoj inacici bilijara?",a:["mosconijev kup","mosconi cup"],p:["mosconi"],e:"Mosconi Cup je godisnjo natjecanje u devetki (nine-ball billiards) izmedju tima Europe i SAD-a, odrzava se od 1994. Nazvano je po Willie Mosconiju, legendi americke bilijarske scene."},
  {n:396,q:"Referirirajuci se naslovom na cesto ponavljan stih u novozavjetnom Otkrivenju, kako se zove nagraduivani <strong>film</strong> Elema Klimova iz 1985., jedan od najemocionalnih prikaza brutalnosti ratnih strahota?",a:["idi i gledaj","come and see","idi i smotri"],p:["idi i gledaj","come and see","idi i smotri"],e:"Idi i gledaj (Idi i smotri, 1985.) je sovjetski ratni film Elema Klimova o navozu nacisticke invazije iz perspektive bjeloruskog djecaka. Smatra se jednim od najjacih ratnih filmova ikad."},
  {n:397,q:"Roden kao Arnold George Dorsey, kako se zove britanski <strong>pop-pjevac</strong>, poznat po hitovima Release me i The Last Waltz, koji je artisticko ime posudio od njemackog skladatelja iz 19. st. (opera Ivica i Marica)?",a:["engelbert humperdinck","humperdinck","engelbert"],p:["humperdinck","engelbert"],e:"Engelbert Humperdinck (rod. 1936. kao Arnold Dorsey) britanski je pop pjevac koji je pozajmio ime njemackog skladatelja Engelberta Humperdincka (1854-1921), autora opere Hänsel und Gretel."},
  {n:398,q:"Podrijetlom iz grckog jezika za 'isto' i 'ime', koji je <strong>znanstveni naziv</strong> biljne ili zivotinjske vrste koji cini dvije iste rijeci, primjerice Rattus rattus ili Axis axis?",a:["tautonim","tautonym"],p:["tautonim","tautonym"],e:"Tautonim je vrsta binomne nomenklature u kojoj su genericki naziv i vrsetna oznaka iste rijeci. Primjerice Gorilla gorilla (goriila) ili Pica pica (svraka). U botanici su tautonomi zabranjeni."},
  {n:399,q:"Prema glazbalu koje su svirali, kako su se zvali slijepi <strong>putujuci sviraci</strong> u 19. st. koji su izvodili ukrajinske narodne pjesme, a ime dijele sa zbirkom pjesama Tarasa Ševcenka iz 1840.?",a:["kobzari","kobzar"],p:["kobzari","kobzar"],e:"Kobzari su bili putujuci slijepi glazbenici u Ukrajini koji su svirali kobzu ili banduru i pjevali historijse epove. Taras Ševcenko naslovio je svoju prvu zbirku pjesama Kobzar (1840.)."},
  {n:400,q:"Kako se, prema americkom sociologu Stephenu, zove tzv. <strong>zakon</strong> eponimije po kojemu se niti jedno znanstveno otkrice ne zove po onomu tko ga je doista otkrio?",a:["stiglerov zakon eponimije","stiglerov zakon","stigler zakon"],p:["stiglerov","stigler"],e:"Stiglerov zakon eponimije je sardonicni zakon koji je formulirao statisticcar Stephen Stigler 1980. Po njemu, niti jedno znanstveno otkrice nije nazvano po svom pravom otkrivatelju. Sam zakon je primjer sebe — Robert Merton formulirao je slicnu ideju ranije."}
];